#!/usr/bin/env node
/**
 * generate-flagship-data-dicts.js
 *
 * Generates data dictionary entries for 10 new flagship metros across all
 * home-services verticals. Each entry contains paragraph-length fields with
 * city-specific details (neighborhoods, utilities, codes, dollar figures).
 *
 * Output: JSON files in data/flagship-new-metros/ that the builder scripts
 * can merge via require().
 *
 * Usage: node scripts/generate-flagship-data-dicts.js
 */

const fs = require("fs");
const path = require("path");
const crypto = require("crypto");

const ROOT = path.resolve(__dirname, "..");
const CTX = JSON.parse(fs.readFileSync(path.join(ROOT, "data/city-context.json"), "utf8"));
const MULT = JSON.parse(fs.readFileSync(path.join(ROOT, "data/city-cost-multipliers.json"), "utf8"));
const LF = JSON.parse(fs.readFileSync(path.join(ROOT, "data/city-local-facts.json"), "utf8"));

function hash(s) { let h = 2166136261; for (let i = 0; i < s.length; i++) h = Math.imul(h ^ s.charCodeAt(i), 16777619) >>> 0; return h; }
function pick(arr, seed) { return arr[seed % arr.length]; }

