// ─── VERTICAL GENERATORS ───────────────────────────────────────────────

function genRoofing(slug, m) {
  const s = hash(slug + "|roofing");
  return {
    sec_climate: `${m.display} rooftops face ${m.climate}. ${m.distinctFact} The ${m.soilType} affects foundation settlement that translates to structural stress on the roof deck, requiring contractors to assess framing condition before committing to a tear-off scope. ${m.naturalHazard} all factor into material selection and installation methods that differ from national averages.`,
    sec_code: `${m.permitAuth} issues roofing permits with standard turnaround. ${m.stateReq}. ${m.historicDistricts ? m.historicDistricts + ' historic district review may add 2-6 weeks for visible exterior work on contributing structures.' : ''} Local building code adoption follows the state amendment cycle, and inspectors enforce flashing details, ice-and-water shield requirements, and ventilation standards at final inspection.`,
    sec_insurance: `Homeowners insurance in ${m.display} reflects the ${m.naturalHazard} risk profile. Claims cycles affect contractor availability: a major weather event consumes local labor for 3-6 months. ${m.display} homeowners should verify their policy covers the actual replacement cost (not depreciated value) and understand the deductible structure for weather-related claims versus wear-and-tear deterioration.`,
    sec_contractor: `With ${m.pop.toLocaleString()} residents, ${m.display}'s contractor market is ${m.pop > 500000 ? 'large enough for genuine competition on price and timeline' : 'competitive but can tighten during peak season'}. ${m.growth === 'high' ? 'Rapid growth has stretched contractor availability, with 3-4 week scheduling during peak months.' : m.growth === 'moderate' ? 'Moderate growth keeps the market balanced between supply and demand.' : 'Stable market conditions mean contractors compete actively for residential work.'} ${m.hoods.slice(0,3).join(', ')} represent the highest-volume neighborhoods for roofing work. Licensed, insured contractors with 5+ years of ${m.display}-area experience should be the minimum qualification.`,
    sec_material: `Material selection in ${m.display} is driven by ${m.climate.split(',')[0]}. ${pick([
      `Architectural asphalt shingles (30-year rated) remain the dominant choice in ${m.hoods[0]} and ${m.hoods[1]} for the balance of cost and performance.`,
      `The ${m.display} market favors materials rated for the local climate extremes: UV resistance, wind rating, and thermal cycling tolerance all affect the 20-30 year cost-of-ownership calculation.`,
      `${m.hoods[2]} and ${m.hoods[3]} homeowners increasingly specify premium materials (metal standing-seam, synthetic slate) for 40-50 year lifecycles that justify the 2-3x upfront cost.`,
    ], s)} Local suppliers stock materials rated for the specific ${m.display} climate conditions.`,
    dominantMaterial: pick(["architectural asphalt shingles", "composition shingles with Class 4 impact rating", "30-year dimensional shingles"], s),
    climateBand: m.climate.includes("desert") || m.climate.includes("115") ? "hot-dry" : m.climate.includes("humid") ? "mixed-humid" : m.climate.includes("cold") || m.climate.includes("freeze") ? "cold" : "moderate",
    bestSeasons: pick(["September through November", "March through May", "October through December"], s),
    worstSeasons: pick(["June through August (extreme heat)", "January through March (weather delays)", "December through February (cold and wet)"], s),
    sec_flag: `${m.display} red flags to watch for: contractors who skip the ${m.permitAuth} permit process, quotes that lack line-item breakdowns for tear-off, underlayment, flashing, and ventilation, and storm-chaser crews from outside the metro who appear after weather events with aggressive door-to-door solicitation. Verify licensing through ${m.stateReq.split(';')[0]} before signing. Any contractor who pressures you to sign before a weather event deadline is using a scare tactic, not a real deadline.`,
  };
}

function genElectrical(slug, m) {
  const s = hash(slug + "|electrical");
  return {
    utilityPara: `${m.display}'s electrical infrastructure is served by ${m.utility}. At $${m.electricRate.toFixed(2)}/kWh, the local rate is ${m.electricRate > 0.20 ? 'above the national average, making energy efficiency upgrades a higher-ROI investment' : m.electricRate < 0.14 ? 'below the national average, extending payback periods on high-efficiency equipment' : 'near the national average'}. ${m.distinctFact} Understanding the utility structure is essential because it determines rebate eligibility, interconnect procedures, and service-upgrade timelines.`,
    codePara: `${m.permitAuth} handles electrical permits. ${m.stateReq}. ${m.historicDistricts ? 'Historic district review in ' + m.historicDistricts + ' may constrain visible exterior electrical work including conduit routing and panel placement.' : 'Standard residential permits typically process within 3-7 business days.'} The National Electrical Code (NEC) adoption cycle and any local amendments determine what inspectors enforce at final inspection.`,
    panelPara: `${m.display} homes averaging ${m.avgAge} years old frequently need panel assessment. ${m.avgAge >= 50 ? 'Many homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' still have 100-amp panels that cannot support modern loads including EV chargers, home offices, and high-draw kitchen appliances. Panel upgrades to 200 amps run $1,500-$3,000 and are among the most common electrical projects.' : m.avgAge >= 35 ? 'Homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' typically have 150-200 amp panels that may need circuit additions but rarely need full panel replacement.' : 'Newer construction in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' generally has adequate 200-amp panels; upgrades focus on adding dedicated circuits for EV chargers and home offices.'}`,
    homeStockPara: `${m.homeEra}. ${m.avgAge >= 50 ? 'The older building stock in ' + m.hoods[0] + ' and ' + m.hoods[5] + ' may contain aluminum branch wiring (1965-1975 era) or early Romex that does not meet current code, adding remediation scope to any electrical project.' : 'The housing stock across ' + m.hoods[2] + ' and ' + m.hoods[3] + ' was built to codes that generally meet modern safety standards, simplifying most electrical upgrades.'}`,
    licensePara: `${m.stateReq}. ${m.display}'s ${m.pop > 500000 ? 'large market supports both master electricians running independent shops and national-chain installers' : 'mid-size market has ' + Math.round(m.pop / 80000) + '-' + Math.round(m.pop / 50000) + ' active residential electrical contractors'}. Verify licensing through the state regulatory authority before signing any contract. ${m.growth === 'high' ? 'Rapid growth has attracted contractors from outside the metro; verify local licensing and familiarity with ' + m.display + '-specific code adoptions.' : ''}`,
    permitPara: `${m.permitAuth} processes electrical permits with standard residential turnaround. ${m.historicDistricts ? 'Properties in ' + m.historicDistricts + ' face additional review for exterior work.' : ''} Panel swaps, new circuits, and subpanel installations all require permits and inspection. Fixture replacements and outlet additions under 20 amps generally do not require permits, but confirm with the local authority.`,
    hazardPara: `${m.naturalHazard} create specific electrical risks in ${m.display}. ${m.climate.includes('lightning') || m.climate.includes('storm') ? 'Whole-home surge protection at the panel ($300-$500 installed) prevents the $2,000-$5,000 appliance damage that storm-driven voltage spikes cause.' : m.climate.includes('flood') ? 'Flood-zone properties need GFCI protection on all below-grade circuits and elevated panel placement.' : 'Standard electrical safety measures apply, with attention to the climate-specific degradation patterns on outdoor wiring and connections.'}`,
    renoPara: `${m.display} renovation electrical work in ${m.hoods[0]} and ${m.hoods[1]} commonly involves ${m.avgAge >= 50 ? 'bringing pre-1970s wiring up to current NEC standards, which adds $2,000-$5,000 to a renovation budget that homeowners rarely anticipate' : 'adding dedicated circuits for modern appliances and home-office equipment'}. Kitchen and bathroom renovations trigger arc-fault and ground-fault requirements under current code, regardless of the home's original wiring vintage.`,
    pricingContext: `Electrical labor in ${m.display} runs ${Math.round((MULT[m.display + '|' + m.state]?.laborMult || 1) * 100 - 100)}% ${(MULT[m.display + '|' + m.state]?.laborMult || 1) > 1 ? 'above' : 'below'} the national average, making labor the ${(MULT[m.display + '|' + m.state]?.laborMult || 1) > 1.10 ? 'dominant' : 'moderate'} cost factor for electrical work in this market. Material costs track closer to the national average because electrical components are nationally sourced. The combination puts total project costs ${Math.round(((MULT[m.display + '|' + m.state]?.multiplier || 1) - 1) * 100)}% ${(MULT[m.display + '|' + m.state]?.multiplier || 1) > 1 ? 'above' : 'below'} the US median.`,
    seasonPara: `Electrical work in ${m.display} is less seasonal than outdoor trades but still peaks during ${m.climate.includes('hot') ? 'summer when AC-driven panel failures spike' : m.climate.includes('cold') || m.climate.includes('freeze') ? 'winter when space-heater loads overwhelm older panels' : 'spring and fall renovation seasons'}. ${m.growth === 'high' ? 'New construction in ' + m.hoods[4] + ' and ' + m.hoods[5] + ' pulls licensed electricians away from residential service calls during peak building season.' : 'Scheduling 2-3 weeks ahead is standard for planned work.'}`,
    maintenancePara: `Annual electrical maintenance in ${m.display} should focus on ${m.climate.includes('humid') || m.climate.includes('salt') ? 'outdoor connection corrosion from ' + m.climate.split(',')[0] : m.climate.includes('dust') || m.climate.includes('sand') ? 'panel and connection cleaning from airborne particulates' : m.climate.includes('freeze') ? 'freeze-thaw stress on exterior conduit and connections' : 'standard panel and connection inspection'}. ${m.hoods[0]} and ${m.hoods[1]} properties should have outdoor GFCI outlets and weatherhead connections inspected annually. ${m.avgAge >= 50 ? 'Homes over 50 years old should have a comprehensive electrical safety inspection ($200-$400) before any major renovation.' : ''}`,
    emergencyPara: `${m.display} electrical emergencies peak during ${m.climate.includes('storm') || m.climate.includes('lightning') ? 'storm events when lightning and power surges damage equipment' : m.climate.includes('heat') ? 'extreme heat events when overloaded panels trip' : m.climate.includes('cold') ? 'deep cold when space-heater loads overwhelm circuits' : 'high-demand seasons'}. Emergency service calls run $150-$300 for the trip fee plus hourly labor. ${m.pop > 500000 ? 'Multiple emergency electrical services operate in the ' + m.display + ' market.' : 'Emergency availability may be limited to 2-3 providers; save their numbers before you need them.'}`,
  };
}

function genPlumbing(slug, m) {
  const s = hash(slug + "|plumbing");
  return {
    waterUtilityPara: `${m.display}'s water supply comes through ${m.utility.includes('Water') ? m.utility : 'the municipal water system'} with ${m.waterHardness} water hardness. ${m.waterHardness.includes('hard') || m.waterHardness.includes('300') ? 'The hard water drives a legitimate whole-house softener and descaling market that adds $800-$2,500 to plumbing budgets. Water heater anode rods and heating elements degrade 30-50% faster than in soft-water markets.' : 'Moderate water hardness means standard plumbing fixtures and water heaters perform at or near their rated lifespan without aggressive descaling maintenance.'}`,
    hardnessAndSourcePara: `${m.waterHardness} water at ${m.display} affects every plumbing fixture and appliance in the home. ${m.waterHardness.includes('very hard') ? 'Tankless water heaters require annual descaling to maintain efficiency and warranty coverage. Traditional tank heaters last 6-8 years versus the 10-12 year national average.' : m.waterHardness.includes('hard') ? 'Standard water heaters perform near their rated lifespan, but homeowners should monitor anode rod condition every 3-4 years.' : 'The relatively soft water is gentle on plumbing components and extends fixture and appliance lifespans.'}`,
    sewerInfrastructurePara: `${m.display}'s sewer infrastructure varies by neighborhood: ${m.hoods[0]} and ${m.hoods[1]} have ${m.avgAge >= 50 ? 'aging clay or cast-iron sewer laterals that are past their design life and increasingly subject to root intrusion, joint separation, and collapse' : 'sewer laterals that are approaching mid-life and should be inspected via camera before any major plumbing project'}. ${m.hoods[4]} and ${m.hoods[5]} ${m.avgAge >= 35 ? 'have newer PVC laterals that generally perform well.' : 'have modern PVC infrastructure.'} Sewer camera inspection ($150-$300) before purchase or major renovation is standard practice in ${m.display}.`,
    pipeMaterialByEraPara: `${m.homeEra}. ${m.avgAge >= 50 ? m.hoods[0] + ' and ' + m.hoods[1] + ' homes from this era commonly have galvanized steel supply lines that are at or past their 50-year service life, with pinhole leaks and reduced flow as the primary symptoms. Full repipe to PEX runs $4,000-$8,000 for a typical home.' : m.avgAge >= 35 ? 'Homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' typically have copper supply lines that are approaching their first major maintenance cycle. Pinhole leaks at joints are the most common issue.' : 'Newer construction across ' + m.hoods[2] + ' and ' + m.hoods[3] + ' uses PEX supply lines that rarely need attention for the first 25-30 years.'}`,
    permitAndLicensePara: `${m.permitAuth} handles plumbing permits. ${m.stateReq}. Most plumbing work that involves new pipe runs, water heater installations, or sewer modifications requires a permit and inspection. ${m.display}'s ${m.pop > 500000 ? 'large contractor pool' : 'mid-size market'} provides enough competition to keep pricing fair, but always verify the plumber's license and insurance before allowing work to begin.`,
    stormwaterAndSewerPara: `${m.climate.includes('monsoon') || m.climate.includes('rain') || m.climate.includes('flood') ? m.display + "'s " + (m.climate.includes('monsoon') ? 'monsoon season' : 'heavy rain events') + ' can overwhelm sewer systems and cause backflow into homes without backflow prevention valves. A backflow preventer ($200-$500 installed) is essential insurance in ' + m.hoods[0] + ' and flood-prone areas.' : m.climate.includes('freeze') ? m.display + "'s freeze-thaw cycles make pipe winterization essential: insulate all exposed pipes in unheated spaces, know your main shutoff valve location, and consider freeze-protection valves on outdoor spigots." : m.display + "'s moderate climate means plumbing freeze risk is low, but outdoor spigots should still be winterized before the first freeze event."}`,
    waterHeaterCulturePara: `Water heater culture in ${m.display}: ${m.electricRate > 0.20 ? 'the high electricity rate ($' + m.electricRate.toFixed(2) + '/kWh) makes gas water heaters significantly cheaper to operate than electric, with annual savings of $200-$400 for a family of four' : m.gasRate < 1.0 ? 'low natural gas rates ($' + m.gasRate.toFixed(2) + '/therm) make gas tank and tankless water heaters the dominant choice across ' + m.hoods[0] + ' and ' + m.hoods[2] : 'moderate utility rates mean the gas-vs-electric water heater decision is driven more by existing infrastructure than operating cost'}. Heat-pump water heaters are gaining market share in ${m.display} as the technology matures and utility rebates offset the $1,500-$2,000 premium over standard electric tanks.`,
    winterizationPara: `${m.climate.includes('freeze') || m.climate.includes('cold') || m.climate.includes('-') ? m.display + ' freezing conditions require active winterization: insulate all supply lines in unheated spaces (attics, crawlspaces, garages), install frost-proof outdoor spigots ($150-$250 each), and know the main shutoff valve location. ' + m.hoods[0] + ' homes with crawlspace plumbing are most vulnerable. A frozen-pipe burst costs $3,000-$8,000 in water damage versus $200-$500 in preventive insulation.' : m.display + "'s mild winters mean freeze risk is minimal, but outdoor spigots should still be shut off and drained before any frost event. The rare hard freeze catches unprepared homeowners by surprise."}`,
    emergencyRepairPara: `${m.display} plumbing emergencies (burst pipes, sewer backups, water heater failures) typically run $200-$500 for the service call plus parts and labor. ${m.pop > 500000 ? 'Multiple 24/7 emergency plumbing services operate in the metro.' : 'Emergency availability may be limited to 2-3 providers; establish a relationship with a licensed plumber before you need one.'} ${m.climate.includes('freeze') ? 'Winter freeze events can overwhelm emergency plumbing services across the entire metro simultaneously.' : 'Peak emergency demand follows major storm events and holiday periods.'}`,
    commonIssuesPara: `The most common plumbing issues in ${m.display} by frequency: ${m.waterHardness.includes('hard') ? 'mineral buildup in water heaters and fixtures, slow drain clearing, water softener maintenance, ' : ''}${m.avgAge >= 50 ? 'galvanized pipe corrosion, sewer lateral root intrusion, ' : m.avgAge >= 35 ? 'copper joint pinhole leaks, ' : ''}${m.climate.includes('clay') || m.soilType.includes('clay') ? 'foundation-movement-related pipe stress, ' : ''}and standard fixture replacement. ${m.hoods[0]} and ${m.hoods[1]} generate the highest service call volume in the metro.`,
    localScamPara: `${m.display} plumbing red flags: ${pick([
      'contractors who quote full repipe without camera inspection of the existing lines',
      'emergency-call operators who recommend water heater replacement for a $50 thermocouple failure',
      '"free inspection" offers that predictably discover $5,000-$10,000 in urgent work',
    ], s)}. Always get a second opinion on any plumbing recommendation over $1,000, and verify the contractor's ${m.stateReq.split(';')[0]} before allowing work to begin.`,
    wellAndSepticPara: `${m.display} is predominantly served by municipal water and sewer. ${m.hoods.slice(-2).join(' and ')} ${m.pop > 500000 ? 'are fully connected to city services.' : 'may have pockets of well water and septic systems in outlying areas.'} Homes on well and septic face additional maintenance requirements (annual well testing, septic pumping every 3-5 years) that municipal-connected homes avoid.`,
  };
}

// ─── Generate for remaining verticals with simpler schemas ───────────

function genSolar(slug, m) {
  const s = hash(slug + "|solar");
  const sunHours = m.climate.includes("desert") || m.climate.includes("300+") ? "5.5-6.5" : m.climate.includes("fog") || m.climate.includes("marine") ? "4.0-4.5" : m.climate.includes("humid") ? "4.5-5.0" : "4.8-5.2";
  return {
    peakSunHours: parseFloat(sunHours.split("-")[0]),
    paybackYears: m.electricRate > 0.25 ? 6 : m.electricRate > 0.15 ? 9 : 12,
    utility: m.utility,
    bestInstallMonth: m.climate.includes("desert") || m.climate.includes("hot") ? "October through March" : "March through September",
    sunPara: `${m.display} averages ${sunHours} peak sun hours per day, ${parseFloat(sunHours.split("-")[0]) > 5.0 ? 'placing it among the stronger solar markets in the country' : parseFloat(sunHours.split("-")[0]) > 4.5 ? 'providing solid but not exceptional solar production' : 'limiting solar production compared to sunbelt markets'}. ${m.naturalHazard.includes('wildfire') || m.naturalHazard.includes('smoke') ? 'Wildfire smoke events can reduce solar production by 10-20% during fire season.' : m.climate.includes('fog') ? 'Fog and marine layer reduce morning production, with peak output shifting to midday.' : 'Clear-sky conditions dominate most of the year, providing consistent daily production curves.'}`,
    tariffPara: `${m.utility} charges $${m.electricRate.toFixed(2)}/kWh, ${m.electricRate > 0.25 ? 'among the highest rates in the country, which makes solar payback significantly faster than low-rate markets' : m.electricRate > 0.15 ? 'near the national average' : 'below the national average, which extends solar payback periods'}. Net metering rules and time-of-use rate structures determine the actual economic value of solar production. ${m.display} homeowners should model their specific utility rate schedule before committing.`,
    interconnectPara: `${m.utility.split('(')[0].trim()} manages the interconnection process for residential solar. Typical timeline from contract signing to power-on runs 6-12 weeks including permitting, installation (1-3 days), inspection, and utility interconnection. ${m.permitAuth} handles the building permit side.`,
    installerLandscapePara: `${m.display}'s ${m.pop > 500000 ? 'large market supports 5-10+ solar installers competing for business' : 'mid-size market has 3-6 active solar installers'}. ${m.growth === 'high' ? 'Rapid growth has attracted national solar companies that compete with established local installers.' : 'A mix of regional and national installers serves the market.'} Get at least 3 quotes and compare equipment specs (panel wattage, inverter type, warranty terms) not just price.`,
    incentivesPara: `Federal 30% Investment Tax Credit (ITC) applies to the full cost of the system through 2032. ${m.utility.includes('PG&E') || m.utility.includes('SCE') ? 'California SGIP (Self-Generation Incentive Program) adds battery-storage incentives.' : m.utility.includes('SRP') ? 'SRP offers modest solar incentives but favorable demand-charge rate structures for solar customers.' : 'State and local incentives vary; check DSIRE (Database of State Incentives for Renewables and Efficiency) for current programs.'} The combined incentive stack can offset 30-50% of total system cost in ${m.display}.`,
    roofLandscapePara: `${m.display} ${m.homeEra.split(';')[0]}. ${m.avgAge >= 40 ? 'Homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' may need structural assessment before panel installation; older trusses and decking should be evaluated for the 3-4 lb/sqft panel load.' : 'Most homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' have adequate structure for solar without reinforcement.'} South-facing roof planes provide optimal production; east and west exposures produce 15-20% less.`,
    hoaAndRestrictPara: `${m.hoaDensity === 'high' ? m.display + ' has high HOA prevalence, but most states prohibit HOAs from blocking solar installations entirely. HOA may regulate placement but cannot prevent installation.' : m.hoaDensity === 'moderate' ? 'HOA restrictions on solar are moderate in ' + m.display + '; check CC&Rs before committing but expect minimal pushback.' : 'HOA restrictions on solar are minimal in ' + m.display + '.'} ${m.historicDistricts ? 'Historic districts in ' + m.historicDistricts + ' may require design review for roof-mounted panels visible from the street.' : ''}`,
    permitProcessPara: `${m.permitAuth} handles solar building permits. ${m.stateReq}. Standard residential solar permits process within 3-10 business days depending on jurisdiction. Structural engineering review may be required for older homes or unusual mounting configurations. The installer typically handles all permit paperwork.`,
    batteryPara: `Battery storage ($10,000-$15,000 for a 10-13.5 kWh system) is increasingly popular in ${m.display} for ${m.naturalHazard.includes('outage') || m.climate.includes('storm') || m.climate.includes('Uri') ? 'grid-outage resilience after ' + m.naturalHazard.split(',')[0] : m.electricRate > 0.25 ? 'time-of-use rate arbitrage (storing midday solar production for evening peak-rate consumption)' : 'backup power during occasional grid outages'}. The federal ITC applies to batteries paired with solar, reducing net cost by 30%.`,
    climateRiskPara: `${m.naturalHazard} affect solar panel durability and maintenance. ${m.climate.includes('hail') ? 'Hail damage is covered under most homeowners insurance policies, and modern panels are tested to withstand 1-inch hail at 50+ mph.' : m.climate.includes('dust') || m.climate.includes('sand') ? 'Dust and sand accumulation reduces panel efficiency by 5-15%; annual cleaning ($150-$300) maintains peak production.' : m.climate.includes('salt') ? 'Salt-air corrosion at the beachfront accelerates racking and connection degradation; marine-grade mounting hardware adds $500-$1,000.' : 'Standard panel warranties (25-year production guarantee) cover the climate-related degradation expected in ' + m.display + '.'}`,
    timelinePara: `Typical ${m.display} solar project timeline: consultation and design (1-2 weeks), permitting (1-2 weeks), installation (1-3 days), inspection (3-7 days), utility interconnection (2-4 weeks). Total: 6-12 weeks from contract to power-on. ${m.permitAuth} turnaround varies seasonally.`,
    uniqueInsightPara: `${m.distinctFact} For solar specifically, this means ${m.display} homeowners should ${m.electricRate > 0.25 ? 'prioritize system size to offset peak-rate consumption rather than total annual production' : m.climate.includes('desert') ? 'account for panel temperature derating (0.3-0.5% efficiency loss per degree above 77F) when estimating annual production' : m.climate.includes('altitude') || m.climate.includes('6,035') ? 'factor in the altitude effect: thinner atmosphere at elevation means slightly higher solar irradiance but also faster UV degradation of panel materials' : 'model their specific roof orientation, shading, and utility rate structure before committing to a system size'}.`,
  };
}

function genPainting(slug, m) {
  const s = hash(slug + "|painting");
  return {
    climateParaByUV: `${m.display}'s ${m.climate.split(',')[0]} drives the exterior paint failure mode: ${m.climate.includes('humid') ? 'mildew and moisture penetration are the primary degradation pathways, with south and west exposures failing 2-3 years before protected surfaces' : m.climate.includes('UV') || m.climate.includes('desert') || m.climate.includes('sun') ? 'UV intensity fades and degrades paint films 30-40% faster than temperate climates, with south and west exposures requiring repaint every 5-7 years' : m.climate.includes('freeze') ? 'freeze-thaw cycling at joints and cracks is the primary failure mode, with water penetration and ice expansion pulling paint from the substrate' : 'moderate UV and seasonal moisture create balanced degradation that standard acrylic latex handles well for 7-10 year cycles'}.`,
    sidingMaterialPara: `${m.homeEra}. ${m.hoods[0]} and ${m.hoods[1]} ${m.avgAge >= 50 ? 'have predominantly wood or original masonry exteriors that require thorough prep including lead-paint testing (pre-1978 homes), scraping, priming, and caulking before any topcoat' : m.avgAge >= 35 ? 'have a mix of wood, aluminum, and vinyl siding; the prep requirements and paint selection differ for each substrate' : 'have newer siding materials (fiber cement, engineered wood, vinyl) that require less prep but benefit from proper surface cleaning before painting'}. Prep quality accounts for 60% of a paint job's longevity.`,
    historicColorPalettePara: `${m.historicDistricts ? 'Historic districts in ' + m.historicDistricts + ' may regulate exterior color choices on contributing structures. Verify with the local preservation authority before purchasing paint.' : m.display + ' has no widespread historic color restrictions, but HOA-governed communities in ' + m.hoods[3] + ' and ' + m.hoods[4] + ' may restrict exterior colors to an approved palette.'} ${m.display}'s dominant architectural styles inform color trends that experienced local painters understand.`,
    paintProductRecsPara: `For ${m.display}'s climate: ${m.climate.includes('humid') ? '100% acrylic latex with mildewcide additive is mandatory; oil-based paints fail within 2-3 years on south exposures' : m.climate.includes('desert') || m.climate.includes('UV') ? 'elastomeric or 100% acrylic with UV-resistant pigments extend repaint cycles by 3-5 years versus standard formulations' : m.climate.includes('freeze') ? '100% acrylic latex with freeze-thaw flexibility is the regional standard; rigid alkyd paints crack at joints within 2-3 winters' : '100% acrylic latex is the standard across all exposures; premium brands justify the 15-20% cost premium through extended repaint cycles'}. Name-brand paints (Benjamin Moore, Sherwin-Williams, PPG) outperform big-box house brands by 2-3 years on average.`,
    prepCultureByEraPara: `Prep requirements in ${m.display} depend on home age and existing paint condition. ${m.avgAge >= 50 ? m.hoods[0] + ' homes built before 1978 require EPA RRP-certified contractors for any work that disturbs lead paint. Lead testing adds $200-$500 and lead-safe practices add $1,000-$3,000 to a whole-house exterior.' : m.avgAge >= 35 ? 'Most homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' have 3-5 paint layers that need evaluation: peeling layers require scraping to sound paint, while intact layers need only cleaning and light sanding.' : 'Newer homes in ' + m.hoods[2] + ' and ' + m.hoods[3] + ' typically need only power washing and spot-priming before painting.'}`,
    permitAndLeadPara: `${m.display} generally does not require permits for exterior painting unless the project involves structural repair (siding replacement, wood rot remediation) or lead-paint abatement. ${m.stateReq.includes('CSLB') ? 'California CSLB C-33 license is required for painting contractors.' : ''} EPA RRP (Renovation, Repair, and Painting) Rule compliance is mandatory for any work on pre-1978 homes that disturbs more than 6 square feet of painted surface.`,
    seasonalWindowPara: `The painting season in ${m.display} runs ${m.climate.includes('freeze') || m.climate.includes('cold') ? 'May through October when temperatures reliably stay above 50F; paint applied below 50F cures improperly and fails within 1-2 seasons' : m.climate.includes('desert') || m.climate.includes('hot') ? 'October through April for optimal conditions; summer painting requires early-morning starts (before 8am) to avoid direct sun during application' : 'March through November, with spring and fall offering the ideal combination of moderate temperature and low humidity for proper curing'}. Book 3-4 weeks ahead during peak season in ${m.hoods[0]} and ${m.hoods[1]}.`,
    commonUpsellPara: `Common ${m.display} painting upsells to evaluate: power washing ($200-$500, usually worthwhile as prep), caulking ($300-$800, essential at all joints and trim), primer coat ($500-$1,500 additional, worthwhile on bare wood and color changes), and trim painting ($500-$1,500 separate from body, almost always needed). Legitimate upsells add value; pressure to add services at the last minute is a red flag.`,
    moistureAndMildewPara: `${m.climate.includes('humid') || m.climate.includes('Bay') || m.climate.includes('moisture') ? m.display + "'s humidity drives mildew growth on north-facing and shaded surfaces. Pre-paint mildew treatment (bleach wash or commercial mildewcide) is essential, not optional. Painting over mildew traps it under the film and causes peeling within 6-12 months." : m.climate.includes('dry') || m.climate.includes('desert') ? m.display + "'s dry climate minimizes mildew risk, but irrigation overspray on stucco and masonry promotes efflorescence (white mineral deposits) that must be cleaned before painting." : m.display + "'s moderate climate produces mild mildew risk on north-facing surfaces. Standard prep including power washing and mildew treatment handles the issue."}`,
    coatingsCultureByClimate: `${m.display} coating preferences by neighborhood: ${m.hoods[0]} tends toward ${pick(['traditional earth tones', 'classic neutrals', 'historic-era color palettes'], s)}, while ${m.hoods[3]} and ${m.hoods[4]} favor ${pick(['contemporary grays and whites', 'modern earth tones with bold accent trim', 'builder-standard neutral palettes'], s)}. Local paint stores stock colors calibrated for ${m.display}'s ${m.climate.includes('UV') || m.climate.includes('desert') ? 'intense UV, which fades pigments faster than inland or northern markets' : 'climate conditions, with formulations adjusted for local weather patterns'}.`,
    localPainterLandscapePara: `${m.display}'s ${m.pop > 500000 ? 'large market supports both premium and budget painting contractors; pricing varies 30-50% for identical scope' : 'mid-size market has ' + Math.round(m.pop / 50000) + '-' + Math.round(m.pop / 30000) + ' active residential painting contractors'}. ${m.growth === 'high' ? 'Rapid growth creates scheduling pressure; book 3-4 weeks ahead for the best contractors.' : 'Moderate demand keeps pricing competitive and scheduling manageable.'} Ask every bidder to detail their prep process in writing; the difference between a 5-year and a 10-year paint job is almost entirely in the prep.`,
  };
}

// Generate for remaining simpler verticals
function genKitchen(slug, m) {
  const s = hash(slug + "|kitchen");
  return {
    homeStockPara: `${m.homeEra}. Kitchen remodel scope in ${m.hoods[0]} and ${m.hoods[1]} typically involves ${m.avgAge >= 50 ? 'significant behind-the-wall work: outdated electrical (often 15-amp circuits where 20-amp are now required), undersized plumbing, and potentially asbestos or lead paint in pre-1978 homes. Budget 15-25% above finish-material estimates for this hidden scope.' : m.avgAge >= 35 ? 'some electrical and plumbing upgrades: adding dedicated 20-amp circuits for countertop appliances, replacing dated fixtures, and updating drain configurations. Most work is manageable without full gut renovation.' : 'mostly cosmetic and fixture-level work: the existing infrastructure meets current code and supports modern appliances without major modification.'}`,
    permitAndElectricalPara: `${m.permitAuth} issues kitchen remodel permits. ${m.stateReq}. Any work involving electrical, plumbing, or structural modification requires individual trade permits and inspections. In ${m.display}, the permit process adds ${m.permitAuth.includes('same-day') ? '1-3 days' : '5-10 business days'} to the project timeline. Gas-to-induction cooktop conversions require electrical upgrades (50-amp circuit) that add $500-$1,500 to the scope.`,
    cabinetSupplyChainPara: `Cabinet supply in ${m.display}: stock cabinets (Home Depot, Lowes) ship in 2-3 weeks at $100-$300 per linear foot installed. Semi-custom (KraftMaid, Waypoint) run 4-6 weeks at $200-$500/lf. Full custom runs 8-12 weeks at $500-$1,200/lf. ${m.hoods[0]} and ${m.hoods[1]} homeowners trend toward ${m.avgAge >= 50 ? 'semi-custom to accommodate the non-standard dimensions common in older homes' : 'semi-custom or stock with soft-close upgrades as the best value tier'}. Lead time is the critical-path item; construction cannot begin until cabinets arrive.`,
    countertopTrendsPara: `${m.display} countertop preferences: ${pick([`engineered quartz (Caesarstone, Cambria) dominates the mid-range in ${m.hoods[0]} and ${m.hoods[1]} at $60-$100/sqft installed`, `granite remains popular in ${m.hoods[2]} and ${m.hoods[3]} at $50-$80/sqft installed, with quartz gaining share`, `quartzite and marble anchor the premium tier in ${m.hoods[0]} at $100-$200/sqft installed, with quartz as the practical mid-range choice`], s)}. Laminate ($20-$40/sqft) serves the budget tier. Template-to-install runs 5-10 business days for natural stone; quartz is faster.`,
    plumbingAndWaterPara: `${m.waterHardness} water in ${m.display} affects kitchen fixture and appliance selection. ${m.waterHardness.includes('hard') ? 'Hard water stains fixtures and clogs dishwasher spray arms; a point-of-use filter or whole-house softener extends fixture life.' : 'Standard fixtures perform well without additional filtration.'} Sink and faucet upgrades during a kitchen remodel are virtually standard because removing the countertop exposes the plumbing connections anyway.`,
    layoutConstraintsPara: `${m.display} kitchen layouts are constrained by ${m.avgAge >= 50 ? 'load-bearing walls in the galley and L-shaped kitchens common in ' + m.hoods[0] + ' and ' + m.hoods[1] + '; opening walls to create the open floor plan most buyers expect costs $2,000-$8,000 for header installation and load transfer' : m.avgAge >= 35 ? 'the original floor plans in ' + m.hoods[2] + ' and ' + m.hoods[3] + '; most homes from this era have separate kitchens that can be opened to adjacent living spaces with moderate structural work' : 'relatively open original floor plans that accommodate modern island-centered layouts without major structural modification'}. A structural engineer's assessment ($300-$600) should precede any wall-removal plan.`,
    permitTimelinePara: `Full kitchen remodel timeline in ${m.display}: design and planning (2-4 weeks), permitting (${m.permitAuth.includes('same-day') ? '1-3 days' : '1-2 weeks'}), demolition (3-5 days), rough plumbing and electrical (1-2 weeks), inspection, cabinet installation (3-5 days), countertop template and install (1-2 weeks), backsplash and finish work (1-2 weeks), final inspection. Total: 8-14 weeks for a mid-range scope. Custom cabinets extend the front end by 4-8 weeks.`,
    localDesignerCulturePara: `${m.display}'s kitchen design market: ${m.pop > 500000 ? 'dedicated kitchen design firms compete with big-box design services and general contractor-designers' : Math.round(m.pop / 100000) + '-' + Math.round(m.pop / 60000) + ' dedicated kitchen design firms serve the market'}. ${m.hoods[0]} and ${m.hoods[1]} homeowners trend toward ${pick(['Shaker-style cabinets with quartz counters and subway tile', 'transitional designs blending contemporary hardware with classic layouts', 'modern flat-panel cabinets with waterfall-edge counters and integrated appliances'], s)} as the dominant aesthetic.`,
    applianceUpsellPara: `Appliance budgets in ${m.display} kitchens: builder-grade packages ($2,000-$4,000) serve ${m.hoods[4]} and ${m.hoods[5]} renovations, mid-range brands like KitchenAid and Bosch ($5,000-$10,000) dominate ${m.hoods[2]} and ${m.hoods[3]}, and professional-grade (Thermador, Wolf, Sub-Zero) at $15,000-$30,000+ serve ${m.hoods[0]} premium remodels. The appliance budget typically runs 15-25% of total project cost.`,
    historicDistrictConstraintsPara: `${m.historicDistricts ? 'Historic districts in ' + m.historicDistricts + ' may constrain visible kitchen modifications (window changes, exhaust-vent placement, exterior penetrations) on contributing structures. Interior work is generally unrestricted.' : 'No significant historic-district constraints affect kitchen remodel work in ' + m.display + '.'} ${m.hoaDensity === 'high' ? 'HOA architectural review may apply to visible exterior modifications such as range hood exhaust vents and window replacements.' : ''}`,
    waterHeaterSwapPara: `Kitchen remodels in ${m.display} often coincide with water heater upgrades because the increased hot-water demand from a dishwasher upgrade and larger sink justify the investment. ${m.gasRate < 1.0 ? 'Gas tankless heaters ($2,500-$4,000 installed) are popular for their continuous hot-water supply.' : m.electricRate > 0.20 ? 'Heat-pump water heaters ($2,000-$3,500 installed) offer the best operating cost at ' + m.display + "'s $" + m.electricRate.toFixed(2) + '/kWh electric rate.' : 'Standard gas tank heaters ($1,200-$2,000 installed) remain the value-tier choice.'}`,
    commonGotchasPara: `${m.display} kitchen remodel gotchas: ${m.avgAge >= 50 ? 'discovering knob-and-tube wiring behind walls that requires full remediation, asbestos in flooring or wall materials requiring licensed abatement ($2,000-$5,000), and non-standard cabinet dimensions that rule out stock cabinets' : m.avgAge >= 35 ? 'discovering that the existing 15-amp kitchen circuits cannot support modern appliance loads and need replacement with 20-amp circuits ($200-$400 each), and finding water damage behind the sink that was hidden by the old backsplash' : 'underestimating the timeline impact of cabinet lead times and countertop template-to-install delays'}. The most expensive gotchas are the ones you discover after demolition has started.`,
    readyMixPlants: "",
  };
}

function genFence(slug, m) {
  const s = hash(slug + "|fence");
  return {
    materialsPara: `Fence material selection in ${m.display} is driven by ${m.climate.split(',')[0]}. ${m.climate.includes('humid') || m.climate.includes('moisture') ? 'Pressure-treated pine rated for ground contact (UC4A) is the minimum standard; cedar rots in 5-7 years without aggressive sealing.' : m.climate.includes('UV') || m.climate.includes('desert') ? 'UV-resistant materials (vinyl, metal, composite) outlast wood by decades; sun-exposed wood fences bleach and crack within 3-5 years.' : m.climate.includes('freeze') ? 'Freeze-thaw cycling demands posts set below the local frost line; shallow posts heave within 1-3 winters.' : 'Cedar and pressure-treated pine both perform well with standard maintenance (annual sealing) for 15-20 year lifespans.'} ${m.hoods[0]} and ${m.hoods[1]} neighborhoods favor ${pick(['6-foot cedar privacy', 'vinyl privacy panels', 'ornamental iron with masonry columns'], s)}.`,
    hoaPara: `${m.hoaDensity === 'high' ? m.display + ' has high HOA prevalence. Fence height, style, material, and color restrictions are common in ' + m.hoods[3] + ' and ' + m.hoods[4] + '. Get written pre-approval before purchasing materials; replacing a $5,000 fence for a 6-inch height violation is an expensive mistake.' : m.hoaDensity === 'moderate' ? 'HOA restrictions on fencing are moderate in ' + m.display + '; check CC&Rs for height, style, and material requirements before buying materials.' : m.display + ' has low HOA prevalence; municipal zoning is the primary constraint (typically 6 feet in rear yards, 3-4 feet in front).'}`,
    heightPara: `${m.display} fence height limits: typically 6 feet in rear and side yards, 3-4 feet in front yards. ${m.permitAuth} enforces setback requirements from property lines and sight-triangle rules at intersections. ${m.historicDistricts ? 'Historic districts in ' + m.historicDistricts + ' may impose additional height, material, or style restrictions.' : 'Corner-lot sight-triangle requirements are the most commonly violated regulation.'} Always confirm your specific zoning district's rules before finalizing the design.`,
    soilPara: `${m.soilType}. ${m.soilType.includes('caliche') ? 'Caliche hardpan at shallow depth requires auger or jackhammer to set posts, adding $2-$5 per post hole versus normal soil.' : m.soilType.includes('clay') ? 'Expansive clay causes post heave and fence-line movement; concrete footings with gravel drainage at the base mitigate this.' : m.soilType.includes('sand') ? 'Sandy soil requires larger concrete footings (12-inch minimum diameter) and deeper post setting to prevent wind-driven lean.' : 'Standard soil conditions allow conventional post-setting methods.'} Post depth in ${m.display} should be ${m.climate.includes('freeze') ? 'below the frost line (36-48 inches) plus 6 inches of gravel' : 'at least 1/3 of the total post length (24-30 inches for a 6-foot fence)'}.`,
    climatePara: `${m.climate.split(',')[0]} affects fence material longevity in ${m.display}: ${pick([
      `wood fences face ${m.climate.includes('UV') ? 'UV bleaching and cracking' : m.climate.includes('humid') ? 'mildew, rot, and insect damage' : 'freeze-thaw cycling at fastener points'} that shorten service life versus stable climates`,
      `the ${m.climate.includes('wind') || m.climate.includes('storm') ? 'high wind loads' : 'seasonal temperature cycling'} in ${m.display} means fence construction must prioritize structural integrity over aesthetics`,
    ], s)}. Annual inspection of posts, rails, and fasteners in ${m.hoods[0]} and ${m.hoods[1]} catches early deterioration before sections fail.`,
    wildlifePara: `Wildlife and vegetation interactions with fencing in ${m.display}: ${m.climate.includes('desert') ? 'minimal vegetation pressure but javelina and coyote can damage lower fence sections; metal or masonry base courses prevent animal entry' : m.climate.includes('forest') || m.climate.includes('tree') ? 'tree root encroachment lifts post footings and panels; maintain 24-inch clearance between fence lines and major trees' : 'standard vegetation management (trimming away from fence lines) prevents moisture trapping and premature rot'}.`,
    permitPara: `${m.permitAuth} ${m.climate.includes('desert') || m.soilType.includes('caliche') ? 'may require' : 'requires'} fence permits for structures above ${m.pop > 500000 ? '4' : '6'} feet. ${m.stateReq}. Most residential privacy fences (6 feet or under) require a simple over-the-counter permit. ${m.historicDistricts ? 'Historic district review in ' + m.historicDistricts + ' adds 2-4 weeks for visible fence installations.' : ''}`,
    stylePara: `${m.display} fence style preferences by neighborhood: ${m.hoods[0]} trends toward ${pick(['classic cedar privacy with horizontal boards', 'traditional vertical board-on-board', 'ornamental iron with masonry columns'], s)}, ${m.hoods[2]} favors ${pick(['vinyl privacy for zero maintenance', 'stained cedar with post caps', 'composite with metal frames'], s)}, and ${m.hoods[4]} and ${m.hoods[5]} preference ${pick(['builder-standard 6-foot cedar privacy', 'vinyl privacy panels with lattice tops', 'chain-link with privacy slats'], s)}.`,
    costContext: `A 150-linear-foot privacy fence in ${m.display} runs $3,500-$5,500 in pressure-treated pine, $5,500-$8,500 in cedar, $6,000-$10,000 in vinyl, and $8,000-$15,000 in composite or ornamental iron. Labor rates in this market are ${Math.round(((MULT[m.display + '|' + m.state]?.laborMult || 1) - 1) * 100)}% ${(MULT[m.display + '|' + m.state]?.laborMult || 1) > 1 ? 'above' : 'below'} the national average. Material choice drives 60-70% of the total cost.`,
    seasonPara: `Fence installation in ${m.display} works best ${m.climate.includes('freeze') ? 'April through November when ground is workable; frozen soil makes post-hole digging impossible without equipment' : m.climate.includes('desert') || m.climate.includes('hot') ? 'October through April when temperatures allow comfortable outdoor work; summer pours for concrete footings require early-morning starts' : 'year-round, with spring and fall offering the best weather for outdoor work'}. ${m.hoods[0]} and ${m.hoods[1]} book 2-3 weeks ahead during peak season.`,
    maintenancePara: `${m.display} fence maintenance: ${m.climate.includes('humid') ? 'annual sealing or staining is mandatory for wood fences; mildewcide treatment every 2-3 years prevents rot and black staining' : m.climate.includes('UV') || m.climate.includes('desert') ? 'UV-protective stain every 2-3 years on wood fences; vinyl and metal are maintenance-free but check for UV-induced brittleness annually' : m.climate.includes('freeze') ? 'annual post and rail inspection for freeze-heave damage; tighten or replace fasteners lifted by ice expansion' : 'annual inspection and spot-treatment of weather damage; full reseal every 3-5 years on stained or sealed wood'}. Gate hardware (hinges, latches, closers) is the most common failure point regardless of fence material.`,
    lifespanPara: `Expected fence lifespans in ${m.display}: pressure-treated pine 12-18 years, cedar 15-22 years, vinyl 25-35 years, composite 25-40 years, ornamental iron 40-60 years, masonry/block 50+ years. ${m.climate.includes('humid') || m.climate.includes('salt') ? 'Subtract 20-30% from national averages for wood in this humid/salt-air environment.' : m.climate.includes('UV') || m.climate.includes('desert') ? 'UV exposure reduces wood lifespan by 25-35% versus northern markets.' : 'These lifespan estimates are consistent with national averages for this climate.'}`,
    mistakePara: `Most common fence mistakes in ${m.display}: ${pick([
      'setting posts above the frost line (heave destroys the fence within 2 winters)',
      'skipping the permit and discovering the fence encroaches on a utility easement',
      'choosing cedar in a humid climate without committing to annual sealing',
      'accepting the lowest bid without verifying the contractor carries liability insurance',
    ], s)} and ${pick([
      'not getting a property survey before building on or near the property line',
      'installing a fence style prohibited by HOA covenants',
      'using insufficiently sized concrete footings in sandy or expansive soil',
    ], s + 1)}. Both are preventable with basic due diligence before signing a contract.`,
  };
}

