function genConcrete(slug, m) {
  const s = hash(slug + "|concrete");
  return {
    soilPara: `${m.display}'s ${m.soilType}. ${m.soilType.includes('clay') ? 'Expansive clay soil is the dominant cost driver for concrete work because improper sub-base preparation on clay leads to heave and cracking within 2-5 years. A 4-6 inch compacted gravel sub-base is mandatory in ' + m.hoods[0] + ' and ' + m.hoods[1] + '.' : m.soilType.includes('caliche') ? 'Caliche hardpan at shallow depth affects excavation costs for any below-grade concrete work. Flatwork on caliche-supported soil is generally stable once the sub-base is properly prepared.' : m.soilType.includes('sand') ? 'Sandy soils require proper compaction and moisture control during sub-base preparation. Without adequate compaction, concrete slabs develop settlement cracks within 3-5 years.' : 'Standard soil conditions support conventional concrete sub-base preparation methods. A 4-inch compacted gravel sub-base is the regional standard for residential flatwork.'}`,
    mixPara: `Concrete mix specifications for ${m.display}: ${m.climate.includes('freeze') ? 'air-entrained mix (5-7% air content) is mandatory for all exterior flatwork to resist freeze-thaw spalling; standard mixes without air entrainment fail within 2-3 winters of ' + m.display + "'s " + (m.climate.includes('200') ? '200+' : '50+') + ' annual freeze-thaw cycles' : m.climate.includes('desert') || m.climate.includes('hot') ? 'hot-weather mix design with retarders and curing compounds is essential for pours during the ' + (m.climate.includes('100') ? '30-45 days above 100F' : 'extended summer heat period') + '; standard mixes set too fast in direct sun above 90F, causing surface cracking' : 'standard 3,000-4,000 PSI mix serves most residential applications; specify 4,500 PSI for driveways that support heavy vehicles'}. Ready-mix suppliers serving ${m.hoods[0]} and ${m.hoods[2]} provide same-day delivery for residential pours.`,
    rebarPara: `Reinforcement standards in ${m.display}: ${m.soilType.includes('clay') || m.soilType.includes('expansive') ? '#4 rebar on 18-inch centers with fiber mesh is the local standard for driveways and patios on expansive soil; skipping rebar on clay soil is the single most common cause of premature cracking' : 'fiber mesh reinforcement serves most residential flatwork; #4 rebar on 24-inch centers for driveways supporting heavy vehicles and structural slabs'}. Expansion joints every 10-12 feet on driveways and 8-10 feet on walkways prevent the random cracking that temperature cycling causes in ${m.display}'s climate.`,
    climatePara: `${m.climate.split(',')[0]} affects concrete performance in ${m.display}: ${m.climate.includes('freeze') ? 'freeze-thaw cycling is the primary degradation mechanism; road salt from driveways accelerates surface spalling and requires annual sealer application' : m.climate.includes('desert') || m.climate.includes('hot') ? 'extreme heat during curing causes rapid moisture loss that produces surface cracking; proper curing (keeping concrete moist for 7 days) is essential' : m.climate.includes('humid') ? 'high humidity actually improves curing conditions but promotes algae and mold growth on concrete surfaces; annual pressure washing maintains appearance' : 'moderate seasonal cycling allows year-round pours with standard practices'}. ${m.hoods[0]} and ${m.hoods[1]} concrete work should specify climate-appropriate additives.`,
    disasterPara: `${m.naturalHazard} affect concrete infrastructure in ${m.display}. ${m.naturalHazard.includes('flood') || m.naturalHazard.includes('storm') ? 'Flood and storm events can undermine slabs and expose sub-base; post-event inspection should check for void formation under existing concrete.' : m.naturalHazard.includes('earthquake') ? 'Seismic activity can crack and shift concrete slabs; post-earthquake inspection for foundation and flatwork is recommended.' : m.naturalHazard.includes('hail') ? 'Hail rarely damages concrete directly but hail-storm associated flooding can undermine sub-bases.' : 'Standard maintenance addresses the climate-specific degradation patterns.'} ${m.display} homeowners should inspect concrete annually for new cracks, settlement, and surface deterioration.`,
    permitPara: `${m.permitAuth} handles concrete permits in ${m.display}. ${m.stateReq}. Most residential flatwork (driveways, patios, walkways) requires a simple over-the-counter permit. Structural slabs, retaining walls over 4 feet, and work within setback zones require engineering review. ${m.historicDistricts ? 'Historic districts in ' + m.historicDistricts + ' may review decorative concrete and hardscape designs.' : ''}`,
    setbackPara: `${m.display} zoning requires minimum setbacks from property lines for structures including concrete patios and covered slabs. Check ${m.permitAuth} for your specific lot's setback requirements. ${m.hoaDensity === 'high' ? 'HOA restrictions in ' + m.hoods[3] + ' and ' + m.hoods[4] + ' may further limit hardscape coverage and specify approved materials and finishes.' : ''} Utility easement encroachment is the most common permit rejection reason for concrete work.`,
    stylePara: `Decorative concrete trends in ${m.display}: ${m.hoods[0]} favors ${pick(['stamped concrete in natural stone patterns', 'exposed aggregate with earth-tone pebble mix', 'stained concrete with geometric scoring'], s)}, while ${m.hoods[2]} and ${m.hoods[3]} trend toward ${pick(['brushed finish with integral color', 'stamped ashlar slate pattern', 'modern gray with clean saw-cut control joints'], s)}. Standard broom-finish serves the budget tier at $6-10/sqft versus $12-20/sqft for decorative options.`,
    decorativePara: `${m.display} decorative concrete pricing: stamped concrete ($12-18/sqft), exposed aggregate ($10-15/sqft), stained concrete ($8-14/sqft), and polished concrete ($6-12/sqft for existing slabs). The decorative premium over standard broom-finish ($6-10/sqft) is 40-100% but adds significant curb appeal. ${m.hoods[0]} and ${m.hoods[1]} homeowners see the highest ROI on decorative concrete because the property values support the investment.`,
    seasonPara: `Concrete pouring season in ${m.display}: ${m.climate.includes('freeze') || m.climate.includes('cold') ? 'May through October when overnight temps stay above 40F; cold-weather pours require heated enclosures that add 20-30% to labor' : m.climate.includes('hot') || m.climate.includes('desert') ? 'October through April for optimal curing; summer pours require early-morning starts (before 8am) and aggressive curing protocols' : 'year-round with spring and fall offering ideal curing conditions'}. ${m.hoods[0]} and ${m.hoods[1]} book 2-3 weeks ahead during peak season.`,
    scenarioNotes: `Common ${m.display} concrete projects: driveway replacement ($4,000-$8,000 for 400-600 sqft), patio pour ($2,000-$5,000 for 200-400 sqft), walkway ($1,000-$3,000 for 100-200 sqft), and retaining wall ($200-$400 per linear foot for 4-foot height). ${m.display}'s labor rates run ${Math.round(((MULT[m.display + '|' + m.state]?.laborMult || 1) - 1) * 100)}% ${(MULT[m.display + '|' + m.state]?.laborMult || 1) > 1 ? 'above' : 'below'} national averages. Demolition and removal of existing concrete adds $2-4/sqft.`,
    readyMixPlants: `${m.display}-area ready-mix suppliers typically deliver within 2-3 hours of ordering for residential pours. Minimum load charges ($150-$250 for under 3 cubic yards) apply to small projects. ${m.pop > 500000 ? 'Multiple competing plants keep delivery pricing competitive.' : 'Limited supplier options may add $50-$100 to delivery charges for remote ' + m.display + ' neighborhoods.'}`,
    maintenancePara: `${m.display} concrete maintenance: ${m.climate.includes('freeze') ? 'annual sealer application protects against freeze-thaw spalling and road-salt damage; re-seal every 2-3 years on driveways exposed to de-icing chemicals' : m.climate.includes('humid') || m.climate.includes('rain') ? 'annual pressure washing removes mold and algae growth; apply sealer every 3-5 years to prevent moisture penetration' : m.climate.includes('UV') || m.climate.includes('desert') ? 'UV-resistant sealer every 2-3 years prevents surface chalking and color fading on decorative concrete' : 'sealer application every 3-5 years maintains appearance and extends service life'}. Crack repair ($2-$5 per linear foot) should be done immediately to prevent water infiltration and sub-base erosion.`,
    commonMistakePara: `Most common concrete mistakes in ${m.display}: ${pick(['skipping the compacted gravel sub-base on expansive clay soil', 'pouring in direct sun above 90F without retarder or curing compound', 'insufficient expansion joints that cause random mid-slab cracking', 'accepting a quote without specifying air-entrainment for exterior flatwork'], s)} and ${pick(['not verifying the contractor carries liability insurance', 'choosing the lowest bid without checking reinforcement specifications', 'watering new concrete too aggressively during the curing period'], s + 1)}. Both are preventable with basic specification review before the pour.`,
  };
}

function genFoundation(slug, m) {
  const s = hash(slug + "|foundation");
  return {
    soilGeologyPara: `${m.display} foundation performance is dominated by ${m.soilType}. ${m.soilType.includes('clay') ? 'Expansive clay is the primary cause of foundation distress across ' + m.hoods[0] + ' and ' + m.hoods[1] + '; seasonal moisture cycling causes the clay to swell and shrink, creating the heave-and-settlement patterns that crack foundations, displace door frames, and produce diagonal drywall cracks.' : m.soilType.includes('caliche') ? 'Caliche hardpan provides stable bearing capacity for foundations but complicates any underpinning or piering work that requires below-grade excavation.' : m.soilType.includes('sand') ? 'Sandy soils provide moderate bearing capacity but are susceptible to erosion and settlement when drainage patterns change.' : 'The local soil conditions produce moderate foundation challenges that standard repair methods address effectively.'} A geotechnical soil report ($300-$600) should precede any major foundation work.`,
    failureModePara: `The dominant foundation failure modes in ${m.display}: ${m.soilType.includes('clay') ? 'differential settlement from uneven moisture distribution (one side of the house stays wet while the other dries out), producing diagonal cracks from window and door corners, sticking doors, and visible slab slope' : m.climate.includes('freeze') ? 'frost heave pushing shallow foundation elements upward, producing horizontal cracks in basement walls and uneven floor surfaces' : m.climate.includes('flood') || m.climate.includes('storm') ? 'erosion and washout undermining foundation bearing surfaces during heavy rain events' : 'age-related settlement as original backfill compresses and sub-grade soil consolidates under the structure weight'}. ${m.hoods[0]} and ${m.hoods[1]} homes averaging ${m.avgAge} years are at the age where these issues typically manifest.`,
    repairMethodPara: `Foundation repair methods available in ${m.display}: pressed-pile piering ($1,500-$2,500 per pier) for settlement stabilization, helical piers ($2,000-$3,500 per pier) for both stabilization and lift, mudjacking ($500-$1,500 per section) for minor slab leveling, and polyurethane foam injection ($1,000-$3,000 per zone) for slab stabilization without excavation. ${m.soilType.includes('clay') ? 'On expansive clay in ' + m.hoods[0] + ' and ' + m.hoods[1] + ', pressed-pile piering to stable soil below the active zone is the most common repair.' : 'The choice of method depends on the failure mode, soil conditions, and budget.'}`,
    permitAndEngineeringPara: `${m.permitAuth} handles foundation repair permits in ${m.display}. ${m.stateReq}. Structural engineering assessment ($300-$600) should precede any foundation contractor's scope recommendation. ${m.display}'s ${m.pop > 500000 ? 'large market' : 'mid-size market'} has ${m.pop > 500000 ? 'both national foundation chains and independent structural contractors' : 'a mix of regional and independent foundation contractors'}. National chains offer warranty programs and financing; independent contractors typically quote 20-40% lower for the same scope.`,
    drainagePara: `Drainage management is the #1 preventive measure for foundation health in ${m.display}. ${m.soilType.includes('clay') ? 'Proper grading (6 inches of fall in the first 10 feet from the foundation), functional gutters with downspout extensions, and foundation watering during drought prevent the moisture cycling that drives clay movement.' : m.climate.includes('rain') || m.climate.includes('humid') ? 'Perimeter drains ($3,000-$6,000), sump pumps ($1,500-$3,500), and proper grading redirect water away from the foundation.' : 'Standard surface drainage (proper grading and functional gutters) addresses most moisture-related foundation risks.'} ${m.hoods[0]} and ${m.hoods[1]} properties should have drainage assessed during any foundation evaluation.`,
    seasonalPara: `Foundation repair in ${m.display}: ${m.climate.includes('freeze') ? 'June through September provides stable ground conditions for excavation and piering; avoid late fall and winter unless the repair is an emergency' : m.climate.includes('desert') || m.soilType.includes('clay') ? 'avoid repair during the wettest season when soil is most swollen, as piering into swollen clay overestimates bearing capacity; dry-season repairs produce more accurate load transfer' : 'year-round repair is feasible, with dry weather providing the best conditions for any work requiring excavation'}. Emergency stabilization (e.g., propping a settling corner) can happen in any season.`,
    localDisasterPara: `${m.naturalHazard} affect foundation performance in ${m.display}. ${m.naturalHazard.includes('flood') || m.naturalHazard.includes('rain') ? 'Heavy rain events saturate soil and accelerate differential settlement; post-flood foundation inspection catches damage before it progresses.' : m.naturalHazard.includes('earthquake') ? 'Seismic events can crack foundations and shift slab elements; post-earthquake assessment should include both visible inspection and level survey.' : m.naturalHazard.includes('drought') || m.soilType.includes('clay') ? 'Extended drought causes clay soil shrinkage that pulls away from foundations, creating settlement. Foundation watering during dry months prevents the worst damage.' : 'Standard seasonal weather patterns produce gradual foundation stress that annual inspection catches early.'}`,
    neighborhoodFailurePattern: `${m.display} foundation issues by neighborhood: ${m.hoods[0]} and ${m.hoods[1]} (${m.avgAge >= 50 ? 'homes averaging ' + m.avgAge + ' years, original foundations showing age-related settlement' : 'homes on ' + m.soilType.split(',')[0] + ', subject to soil-driven movement'}) generate the highest repair volume. ${m.hoods[4]} and ${m.hoods[5]} (${m.avgAge >= 35 ? 'newer construction with better foundation engineering' : 'recent construction to modern code'}) have lower incidence but are not immune to soil-driven issues.`,
    warrantyCulturePara: `Foundation repair warranties in ${m.display}: ${m.pop > 500000 ? 'national chains (Olshan, Ram Jack, Foundation Repair of CA) offer lifetime transferable warranties that add resale value; independent contractors typically provide 10-25 year warranties' : 'the mix of regional and independent contractors means warranty terms vary widely from 5 years to lifetime transferable'}. The warranty is only as good as the company behind it; verify the contractor's financial stability and years in the ${m.display} market before weighting warranty terms in your decision.`,
    pieringAlternativesPara: `Not all ${m.display} foundation issues require piering. ${pick(['Carbon-fiber strapping ($3,000-$6,000) stabilizes bowing basement walls without excavation.', 'Polyurethane foam injection ($1,000-$3,000 per zone) levels minor slab settlement without excavation.', 'Mudjacking ($500-$1,500 per section) addresses minor exterior slab settlement at a fraction of piering cost.'], s)} A structural engineer's assessment ($300-$600) determines whether the issue requires full piering or responds to less invasive methods. ${m.hoods[0]} and ${m.hoods[1]} issues often start with drainage correction ($1,000-$3,000) before escalating to structural repair.`,
    moistureManagementPara: `${m.display} foundation moisture management: ${m.soilType.includes('clay') ? 'maintain consistent soil moisture around the foundation perimeter; the goal is preventing the wet-dry cycling that drives clay movement, not keeping soil saturated. A soaker hose on a timer ($50-$100) during drought months prevents $10,000+ in repair costs.' : m.climate.includes('humid') || m.climate.includes('rain') ? 'manage excess moisture through proper drainage, dehumidification of below-grade spaces, and vapor barriers in crawlspaces.' : m.climate.includes('desert') ? 'the primary moisture challenge is rapid evaporation that leaves soil pockets dry against the foundation; consistent irrigation at the foundation perimeter prevents differential settlement.' : 'standard drainage management (gutters, grading, downspout extensions) addresses the majority of moisture-related foundation concerns.'} ${m.hoods[0]} homes should have a moisture management plan as part of any foundation assessment.`,
    localScamPara: `${m.display} foundation repair red flags: ${pick([
      'contractors who recommend piering without providing a structural engineering assessment',
      '"free inspection" operators who consistently find $15,000-$25,000 in urgent work',
      'quoting a fixed pier count before soil testing or level survey',
    ], s)}. Always get an independent structural engineer's assessment ($300-$600) before accepting any contractor's recommended scope. The engineer works for you, not the repair company. ${m.stateReq.includes('license') ? 'Verify the contractor\'s license through the state regulatory authority.' : ''}`,
  };
}

function genGarageDoor(slug, m) {
  const s = hash(slug + "|garage-door");
  return {
    archIntro: `Garage door styles in ${m.display}`,
    archBody: `${m.display}'s dominant architectural styles drive garage door selection: ${m.hoods[0]} and ${m.hoods[1]} favor ${pick(['traditional raised-panel steel in earth tones', 'Craftsman-style carriage doors with decorative hardware', 'contemporary flush-panel aluminum with glass inserts'], s)}, while ${m.hoods[4]} and ${m.hoods[5]} trend toward ${pick(['builder-standard white raised-panel', 'insulated steel in neutral colors', 'modern long-panel designs'], s + 1)}. ${m.hoaDensity === 'high' ? 'HOA architectural review in ' + m.hoods[3] + ' and ' + m.hoods[4] + ' may restrict door style, color, and material.' : 'Municipal regulations focus on structural requirements rather than aesthetics.'}`,
    insulationIntro: `Insulation for ${m.display} garages`,
    insulationBody: `${m.climate.includes('freeze') || m.climate.includes('cold') ? 'Insulated doors (R-12 minimum, R-18+ preferred) make a measurable difference in ' + m.display + "'s winters, especially for attached garages with living space above. Uninsulated doors allow cold-air infiltration that increases heating costs and can freeze exposed plumbing." : m.climate.includes('desert') || m.climate.includes('hot') ? 'Insulated doors (R-12+) reduce heat transfer in ' + m.display + "'s extreme summer heat, keeping garage temperatures 10-15F below outdoor ambient. This matters for attached garages where heat radiates into the home." : m.climate.includes('humid') || m.climate.includes('salt') ? 'Insulation is less critical for temperature management in ' + m.display + "'s mild climate, but insulated doors provide better wind resistance and noise reduction." : 'Insulated doors (R-12+) provide modest temperature benefits for attached garages and noticeably reduce noise from the opener mechanism.'} Budget $200-$400 additional for insulated versus non-insulated doors of the same style.`,
    openerBody: `${m.display} garage door opener preferences: belt-drive openers ($250-$400 installed) are the quiet standard for attached garages in ${m.hoods[0]} and ${m.hoods[1]}; chain-drive ($200-$300) serves detached garages where noise is not a concern; wall-mount jackshaft openers ($300-$500) free up ceiling space. Smart-enabled openers with Wi-Fi and app control add $50-$100 to the base price. ${m.climate.includes('freeze') ? 'Cold-weather lubricant on springs and tracks prevents the January binding failures common in ' + m.display + '.' : m.climate.includes('hot') ? 'Heat-rated lubricant prevents the summer binding and rail expansion that causes opener strain in ' + m.display + "'s extreme heat." : 'Standard maintenance lubricant on springs and tracks prevents binding and extends component life.'}`,
    codeBody: `${m.permitAuth} regulates garage door replacement in ${m.display}. ${m.stateReq}. Most like-for-like door replacements do not require permits, but changes to opening size, structural headers, or electrical service for new openers may trigger permits and inspection. ${m.climate.includes('hurricane') || m.climate.includes('wind') || m.naturalHazard.includes('wind') ? 'Wind-rated doors meeting local design wind speed requirements may be mandatory; check with ' + m.permitAuth + ' for current wind-speed requirements.' : ''}`,
    dealerBody: `${m.display}'s garage door market: ${m.pop > 500000 ? 'dedicated garage door companies, big-box retailer installation services, and independent contractors all compete' : Math.round(m.pop / 100000) + '-' + Math.round(m.pop / 60000) + ' dedicated garage door companies serve the metro'}. Dedicated companies typically offer the widest selection and fastest service but price 10-20% above big-box options for equivalent products. ${m.hoods[0]} and ${m.hoods[1]} tend toward premium doors through specialty dealers, while ${m.hoods[4]} and ${m.hoods[5]} favor big-box value options.`,
    stormBody: `${m.naturalHazard.includes('wind') || m.naturalHazard.includes('storm') || m.naturalHazard.includes('hail') || m.naturalHazard.includes('hurricane') ? m.display + "'s " + m.naturalHazard.split(',')[0] + ' risk drives specific garage door requirements: wind-rated doors (meeting local design wind speed) and impact-rated glass panels protect against the specific hazards in this market. Insurance carriers may require wind-rated doors for policy compliance.' : m.display + "'s moderate weather risk does not impose specific storm-rating requirements on residential garage doors, but impact-rated glass panels and reinforced tracks add durability for the occasional severe weather event."}`,
    redFlag1: `Any ${m.display} garage door contractor who quotes spring replacement without measuring the existing spring dimensions and door weight is guessing, not sizing.`,
    redFlag2: `Emergency service calls in ${m.display} for broken springs should run $200-$400 total (parts + labor), not $600-$800. If quoted higher, get a second call.`,
    redFlag3: `Contractors who insist on replacing both springs when only one is broken are sometimes right (matched springs wear evenly) but sometimes upselling. If the remaining spring is less than 3 years old, it can usually continue in service.`,
    redFlag4: `${m.display} homeowners report door-to-door operators offering "free safety inspections" that consistently find $500-$1,000 in "urgent" repairs. A legitimate annual inspection costs $75-$125.`,
    redFlag5: `Verify any ${m.display} garage door contractor carries ${m.stateReq.split(';')[0]} and liability insurance before allowing work to begin.`,
    scenarios: `Standard ${m.display} garage door projects: single 2-car door replacement ($800-$2,500 door + $300-$600 install), opener replacement ($250-$500 installed), spring replacement ($200-$400), and full system (door + opener + hardware) at $1,500-$3,500 total. ${m.display}'s labor rates run ${Math.round(((MULT[m.display + '|' + m.state]?.laborMult || 1) - 1) * 100)}% ${(MULT[m.display + '|' + m.state]?.laborMult || 1) > 1 ? 'above' : 'below'} national averages.`,
  };
}

function genGutters(slug, m) {
  const s = hash(slug + "|gutters");
  const rainfall = m.climate.includes('desert') ? 8 : m.climate.includes('dry') ? 12 : m.climate.includes('marine') || m.climate.includes('rain') ? 42 : m.climate.includes('humid') ? 48 : 35;
  return {
    annualRainfall: rainfall,
    rainfallNote: `${m.display} receives approximately ${rainfall} inches of annual precipitation${m.climate.includes('monsoon') ? ', concentrated heavily in the July-August monsoon season with intense short-duration storms' : m.climate.includes('snow') || m.climate.includes('freeze') ? ', including significant snowfall that creates ice-dam risk at eaves' : m.climate.includes('hurricane') || m.climate.includes('storm') ? ', with tropical systems producing 3-6 inch single-event totals that overwhelm undersized gutters' : ', distributed fairly evenly across seasons'}. This precipitation pattern drives gutter sizing, guard selection, and maintenance frequency.`,
    downspoutNote: `${m.display} downspout requirements: ${rainfall > 40 ? 'one downspout per 20 linear feet of gutter (versus 30 feet in dry climates) to handle the heavy rain events' : rainfall > 25 ? 'standard one downspout per 25-30 linear feet serves most homes adequately' : 'downspout spacing can stretch to 35-40 feet given the low precipitation volume'}. Extend downspouts 4-6 feet from the foundation or connect to underground drainage. ${m.soilType.includes('clay') ? 'On ' + m.display + "'s expansive clay soil, downspout extensions are critical -- water pooling at the foundation drives the clay movement that causes foundation damage." : ''}`,
    treeCoverage: m.climate.includes('desert') ? "low" : m.climate.includes('forest') || m.climate.includes('tree') ? "heavy" : "moderate",
    dominantTrees: pick([
      `${m.hoods[0]} and ${m.hoods[1]} have mature tree canopy that drops continuous debris into gutters`,
      `deciduous trees in ${m.hoods[0]} and ${m.hoods[2]} create heavy seasonal leaf drop in October-November`,
      `${m.display}'s urban tree canopy generates a mix of leaf, seed, and small-branch debris`,
    ], s),
    debrisType: m.climate.includes('desert') ? "windblown dust, small gravel, and occasional seed pods from desert landscaping" : m.climate.includes('pine') || m.climate.includes('mountain') ? "pine needles, seed cones, and small branches" : "deciduous leaves, seed pods, and seasonal flower debris",
    bestGuardStyle: pick(["micro-mesh gutter guards", "reverse-curve gutter covers", "mesh screen gutter guards"], s),
    freezeRisk: m.climate.includes('freeze') || m.climate.includes('cold') ? "high" : m.climate.includes('frost') ? "moderate" : "low",
    iceNote: `${m.climate.includes('freeze') || m.climate.includes('cold') ? m.display + "'s " + (m.climate.includes('200') ? '200+' : '50+') + ' annual freeze-thaw cycles create ice-dam risk at eaves. Heated gutter cables ($400-800 per 50 feet installed) prevent the ice backup that tears gutters off the fascia and drives water behind siding. Ice-and-water shield membrane 6+ feet up from the gutter line provides secondary defense.' : m.display + "'s mild winters create minimal ice-dam risk. Standard gutter installation without heated cables serves most homes. The occasional frost event requires attention to downspout drainage but not specialized ice protection."}`,
    cleaningFrequency: rainfall > 40 ? "3-4 times per year" : rainfall > 25 ? "2-3 times per year" : "1-2 times per year",
    cleaningNote: `${m.display} gutter cleaning runs $150-$300 per visit for a typical single-story home. ${m.climate.includes('tree') || m.climate.includes('forest') ? m.hoods[0] + ' and ' + m.hoods[1] + ' homes under heavy tree canopy need 3-4 cleanings per year to prevent overflow and fascia rot.' : 'Two annual cleanings (spring and fall) maintain function for most ' + m.display + ' homes.'} Gutter guards ($5-12 per linear foot for mesh screens, $15-25 for micro-mesh) reduce cleaning frequency by 70-80% and pay back in 3-5 years through eliminated cleaning costs.`,
    buyingBest: m.climate.includes('freeze') ? "July through September" : "January through March",
    buyingWorst: m.climate.includes('freeze') ? "March through May (ice-damage replacement rush)" : "September through November (pre-rainy-season rush)",
    buyingNote: `${pick([
      m.display + ' gutter contractors are busiest during the post-storm replacement rush and pre-rainy-season installation period',
      'Off-season scheduling saves 10-15% on labor and provides faster turnaround in ' + m.display,
      'Book 2-3 weeks ahead during peak season in ' + m.hoods[0] + ' and ' + m.hoods[1],
    ], s)}. Seamless aluminum gutters at $6-12 per linear foot installed are the ${m.display} standard; copper ($20-40/ft) and zinc ($15-25/ft) serve the premium tier.`,
    localInsightPara: `${m.display} gutter market insight: ${m.pop > 500000 ? 'dedicated gutter companies with on-site seamless fabrication machines offer the best value -- they fabricate gutters to exact length at your home, eliminating seam leaks' : 'a mix of dedicated gutter companies and general exterior contractors serve the ' + m.display + ' market'}. ${m.hoods[0]} and ${m.hoods[1]} homes with ${m.avgAge >= 40 ? 'original 30-40 year old gutters are at replacement age' : 'relatively new gutter systems need maintenance rather than replacement'}. ${m.distinctFact}`,
    warrantyPara: `${m.display} gutter warranties: seamless aluminum gutters carry 20-year material warranties from most manufacturers; installation warranties from contractors range from 2 to 10 years. Gutter guards add separate warranty terms. The lifetime transferable warranties from premium manufacturers (Leaf Filter, LeafGuard) command higher upfront cost but provide peace of mind for ${m.hoods[0]} homeowners planning long-term ownership.`,
  };
}

function genInsulation(slug, m) {
  const s = hash(slug + "|insulation");
  return {
    atticStrategyPara: `Attic insulation strategy for ${m.display}: ${m.climate.includes('hot') || m.climate.includes('desert') ? 'radiant barriers cut cooling load 8-12% and should be combined with R-38 to R-49 blown insulation; the intense solar radiation on ' + m.display + "'s roofs makes the attic the primary heat-gain pathway" : m.climate.includes('cold') || m.climate.includes('freeze') ? 'R-49 to R-60 blown insulation is the regional standard; air sealing the attic floor matters more than added insulation depth because convective heat loss through gaps overwhelms the insulation\'s conductive resistance' : 'R-38 to R-49 blown insulation serves most ' + m.display + ' homes; air sealing provides the highest ROI per dollar spent'}. ${m.hoods[0]} and ${m.hoods[1]} homes averaging ${m.avgAge} years typically have ${m.avgAge >= 40 ? 'R-11 to R-19 original insulation that is far below current standards' : 'R-30+ insulation that may benefit from topping up to current code levels'}.`,
    wallStrategyPara: `Wall insulation in ${m.display}: ${m.avgAge >= 50 ? m.hoods[0] + ' and ' + m.hoods[1] + ' homes from the ' + (2026 - m.avgAge) + 's era commonly have minimal or no wall insulation. Dense-pack cellulose injection ($1.50-$3.00/sqft) adds R-13 to R-15 without removing drywall.' : m.avgAge >= 35 ? 'most ' + m.display + ' homes from this era have R-11 to R-13 fiberglass batts in exterior walls; upgrading to dense-pack cellulose or injection foam adds R-3 to R-5 per cavity without wall demolition.' : 'newer construction in ' + m.hoods[2] + ' and ' + m.hoods[3] + ' typically has R-13 to R-21 wall insulation that meets or exceeds current energy code.'} ${m.climate.includes('humid') ? 'Vapor-barrier placement in ' + m.display + "'s humid climate matters: warm-side (interior) in heating-dominant zones, cool-side (exterior) in cooling-dominant zones." : ''}`,
    airSealingPara: `Air sealing is the highest-ROI insulation-adjacent improvement in ${m.display}: a well-air-sealed attic at R-38 outperforms a leaky attic at R-60. ${m.avgAge >= 40 ? 'Common air-leak locations in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' homes include plumbing and wire penetrations through the attic floor, can-light fixtures, attic hatches, and the top plates of interior partition walls.' : 'Even newer homes have air leakage through recessed lights, HVAC penetrations, and electrical boxes.'} Professional air sealing runs $300-$600 and should precede any attic insulation upgrade. A blower-door test ($200-$400) measures the before-and-after improvement.`,
    rebatePara: `${m.display} insulation rebates: ${m.utility.includes('PG&E') ? 'PG&E and BayREN Home+ offer $500-$2,000 for whole-home energy upgrades including insulation; Title 24 compliance drives additional insulation requirements during any remodel.' : m.utility.includes('BGE') ? 'EmPOWER Maryland through BGE offers insulation rebates as part of the Home Performance program.' : m.utility.includes('Dominion') ? 'Dominion Energy offers residential insulation rebates through the Home Energy Check-Up program.' : m.utility.includes('CSU') ? 'Colorado Springs Utilities offers energy efficiency rebates for insulation upgrades through the residential program.' : m.utility + ' offers energy efficiency incentives; check current programs for insulation-specific rebates.'} The federal 25C tax credit covers 30% of insulation costs (up to $1,200/year).`,
    contractorLandscapePara: `${m.display}'s ${m.pop > 500000 ? 'large market has dedicated insulation contractors who do nothing but insulation work -- faster, cheaper, and more knowledgeable about building science than general contractors' : 'mid-size market has ' + Math.round(m.pop / 100000) + '-' + Math.round(m.pop / 60000) + ' active insulation contractors'}. For spray foam, verify the contractor is manufacturer-certified (Icynene, Demilec, Lapolla) -- improper mixing ratios or application thickness cause performance failures that are expensive to remedy. ${m.hoods[0]} and ${m.hoods[1]} homeowners should prioritize contractors with building-science credentials (BPI, RESNET) over general contractors.`,
    commonUpsellPara: `Legitimate ${m.display} insulation upsells to evaluate: attic air sealing ($300-$600, almost always worthwhile), crawlspace encapsulation ($3,000-$8,000, worthwhile in humid climates), rim-joist insulation ($500-$1,500, high ROI in heating-dominant climates), and duct insulation upgrade to R-8 ($800-$1,500, required by code during system replacement in some jurisdictions). Illegitimate upsells: spray-foaming a vented attic without addressing moisture management, and whole-house spray foam when blown-in cellulose would achieve the same performance at 40% of the cost.`,
    historicHomePara: `${m.historicDistricts ? 'Historic district properties in ' + m.historicDistricts + ' face insulation constraints: interior rigid-foam panels may alter room dimensions enough to trigger preservation review, and exterior continuous insulation changes the wall profile.' : 'Older homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' benefit most from insulation upgrades but face unique challenges.'} ${m.avgAge >= 50 ? 'Dense-pack cellulose injection is the preferred wall-insulation method for pre-1970s homes because it fills existing cavities without removing plaster or drywall and provides air-sealing benefits that batts cannot match.' : ''}`,
    codeSnapshotPara: `Current energy code for ${m.display}: ${m.climate.includes('desert') || m.climate.includes('hot') ? 'IECC Climate Zone 2-3 requires R-38 attic and R-13 wall insulation for new construction; existing homes are grandfathered but any renovation triggering permit triggers current-code compliance on the affected area' : m.climate.includes('cold') || m.climate.includes('freeze') ? 'IECC Climate Zone 4-5 requires R-49 attic and R-13+5ci (or R-20) wall insulation for new construction' : 'IECC requirements for the ' + m.display + ' climate zone set minimum attic R-38 and wall R-13 for new construction'}. ${m.stateReq.includes('Title 24') ? 'California Title 24 Part 6 exceeds IECC minimums and requires HERS rater verification.' : ''}`,
    monitoringPara: `Post-insulation performance monitoring in ${m.display}: track utility bills for 3-6 months after upgrades to verify savings. ${m.electricRate > 0.20 ? 'At ' + m.display + "'s $" + m.electricRate.toFixed(2) + "/kWh rate, insulation upgrades produce noticeable bill reductions within the first billing cycle." : 'Moderate utility rates mean savings accumulate over 6-12 months before the improvement is clearly visible in billing data.'} A follow-up blower-door test ($200-$400) verifies the air-sealing improvement. ${m.climate.includes('humid') ? 'Monitor for condensation or moisture issues in the first year after insulation changes, especially in crawlspaces and attics.' : ''}`,
    moistureControlPara: `${m.climate.includes('humid') || m.climate.includes('marine') || m.climate.includes('Bay') ? 'Moisture management is critical in ' + m.display + "'s humid climate: vapor barriers on the wrong side of the insulation trap moisture inside wall cavities, promoting mold growth and structural deterioration. In " + m.display + "'s " + (m.climate.includes('hot') ? 'cooling-dominant' : 'mixed heating/cooling') + " climate, vapor-barrier placement requires building-science expertise." : m.climate.includes('dry') || m.climate.includes('desert') ? m.display + "'s dry climate simplifies moisture management: vapor barriers are less critical because the low humidity rarely creates condensation risk inside wall cavities. The primary concern is preventing wind-driven rain intrusion at wall penetrations." : 'Standard moisture-management practices (proper vapor-barrier placement, ventilation, and drainage) address ' + m.display + "'s moderate humidity levels."} ${m.hoods[0]} ${m.avgAge >= 50 ? 'homes lacking original vapor barriers' : 'homes'} should have moisture conditions assessed before adding insulation.`,
  };
}

function genLandscaping(slug, m) {
  const s = hash(slug + "|landscaping");
  return {
    nativePlantPalettePara: `${m.display} native plant recommendations: ${m.climate.includes('desert') ? 'xeriscape with native desert plants (penstemon, agave, desert marigold, ocotillo) cuts water usage 50-70% versus traditional lawns; many local utilities offer turf-removal rebates ($1-3 per square foot)' : m.climate.includes('humid') ? 'native perennials and grasses adapted to ' + m.display + "'s humidity and rainfall (coneflower, black-eyed Susan, switchgrass) thrive with minimal irrigation once established" : m.climate.includes('marine') || m.climate.includes('forest') ? 'native Pacific Northwest species (rhododendrons, ferns, sword fern, Oregon grape) thrive in the constant moisture with zero irrigation' : 'native and adapted species for ' + m.display + "'s climate reduce water consumption and maintenance costs compared to non-native alternatives"}. ${m.hoods[0]} and ${m.hoods[1]} gardens blend native plants with structured design elements for curb appeal.`,
    soilAmendmentPara: `${m.display} soil conditions: ${m.soilType.split(',')[0]}. ${m.soilType.includes('clay') ? 'Expansive clay requires compost amendment (3-4 inches tilled into the top 8 inches) to improve drainage and reduce compaction. Annual topdressing with compost maintains soil structure.' : m.soilType.includes('sand') ? 'Sandy soil drains too quickly for most plantings; compost amendment and mulch application retain moisture and nutrients.' : m.soilType.includes('caliche') ? 'Caliche hardpan requires raised beds or deep soil amendment for successful planting; trees need planting holes that penetrate through the caliche layer.' : 'Standard soil amendment with compost and mulch supports most planting plans.'} ${m.waterHardness.includes('hard') ? 'Hard water at ' + m.waterHardness.split('(')[1]?.replace(')', '') + ' affects irrigation system components; use drip irrigation with replaceable emitters.' : ''}`,
    irrigationRegsPara: `${m.display} irrigation regulations: ${m.climate.includes('desert') || m.climate.includes('dry') ? m.display + ' water conservation ordinances restrict irrigation schedules and may limit turf area in new installations; check with the local water authority for current watering-day restrictions' : m.climate.includes('humid') || m.climate.includes('rain') ? 'irrigation is supplemental rather than primary; smart controllers with rain sensors prevent overwatering during wet seasons' : 'standard smart irrigation controllers with rain sensors provide efficient water management'}. ${m.utility.includes('rebate') || m.climate.includes('desert') ? 'Water-efficient landscape rebates are available through the local utility.' : ''} Drip irrigation saves 30-50% over spray systems.`,
    hardscapeStylePara: `${m.display} hardscape preferences: ${m.hoods[0]} trends toward ${pick(['natural flagstone patios with native plant borders', 'contemporary concrete pavers with clean lines', 'rustic stone walls with mixed perennial beds'], s)}, while ${m.hoods[2]} and ${m.hoods[3]} favor ${pick(['stamped concrete patios with fire pit surrounds', 'interlocking pavers with built-in seating walls', 'decomposed granite pathways with drought-tolerant plantings'], s + 1)}. Hardscape typically represents 20-30% of a comprehensive landscape project budget.`,
    lawnMaterialPara: `Lawn options in ${m.display}: ${m.climate.includes('desert') || m.climate.includes('dry') ? 'traditional turf lawns are increasingly replaced by ' + (m.climate.includes('desert') ? 'decomposed granite, artificial turf, and xeriscape' : 'drought-tolerant grass varieties and reduced-area turf with native groundcovers') : m.climate.includes('humid') ? 'warm-season grasses (Bermuda, Zoysia, St. Augustine) dominate ' + m.hoods[0] + ' and ' + m.hoods[1] : m.climate.includes('cold') || m.climate.includes('freeze') ? 'cool-season grasses (Kentucky bluegrass, tall fescue) perform best in ' + m.display + "'s climate" : 'a mix of warm and cool-season grasses serves the climate'}. ${m.hoaDensity === 'high' ? 'HOA lawn-maintenance requirements in ' + m.hoods[3] + ' and ' + m.hoods[4] + ' may mandate specific turf types and maintenance standards.' : ''}`,
    turfAndXeriscapeRebatesPara: `${m.climate.includes('desert') || m.climate.includes('dry') ? m.display + ' utility turf-removal rebates: check with the local water authority for current programs offering $1-3 per square foot for converting turf to water-efficient landscaping. These rebates frequently cover 30-50% of the conversion cost.' : m.climate.includes('humid') ? 'Traditional lawn-and-garden landscaping is well-supported by ' + m.display + "'s natural rainfall; supplemental irrigation is primarily for establishment of new plantings." : m.display + ' does not currently offer significant turf-removal rebates, but water-efficient landscaping still reduces long-term maintenance costs and water bills.'}`,
    invasivePestPara: `${m.display} invasive species and pest concerns: ${pick([m.climate.includes('humid') ? 'fire ants, Japanese beetles, and invasive privet are the most common landscape pests across ' + m.hoods[0] + ' and ' + m.hoods[1] : m.climate.includes('desert') ? 'bark scorpions, grubs, and invasive buffelgrass are the primary landscape management challenges' : m.climate.includes('marine') ? 'English ivy, Himalayan blackberry, and slugs are the dominant invasive/pest issues' : 'standard regional pests and invasive species require ongoing monitoring and management', ''], s)}. Integrated pest management (IPM) approaches reduce chemical dependency while maintaining landscape health.`,
    HOAAestheticPara: `${m.hoaDensity === 'high' ? m.display + "'s high HOA prevalence means landscape designs in " + m.hoods[3] + ' and ' + m.hoods[4] + ' must conform to architectural guidelines covering plant height, mulch type, hardscape materials, and tree species. Get HOA pre-approval before purchasing plants or materials.' : m.hoaDensity === 'moderate' ? 'Moderate HOA presence in parts of ' + m.display + ' may restrict front-yard landscaping choices; verify CC&Rs before committing to a design plan.' : m.display + ' has minimal HOA restrictions on landscaping; municipal codes governing tree removal, setbacks, and impervious-surface coverage are the primary regulatory constraints.'}`,
    treeServicePara: `Tree work in ${m.display}: ${m.avgAge >= 40 ? 'mature trees on ' + m.hoods[0] + ' and ' + m.hoods[1] + ' properties may need pruning ($300-$1,500 per tree), removal ($500-$3,000 per tree), or hazard assessment ($100-$300) as they age' : 'developing tree canopy on newer properties needs formative pruning to establish good structure'}. ${m.display} ${m.permit ? 'may require' : 'does not typically require'} permits for tree removal on private property, but heritage tree ordinances protect certain species. ISA-certified arborists ($150-$300 for consultation) provide independent assessment versus tree-service companies who profit from removal.`,
    seasonalMaintenancePara: `${m.display} landscape maintenance calendar: ${m.climate.includes('desert') ? 'spring (March-April) is planting season; summer maintenance focuses on irrigation management; fall (October-November) is the secondary planting window' : m.climate.includes('cold') || m.climate.includes('freeze') ? 'spring (April-May) cleanup and planting after last frost; summer watering and maintenance; fall (September-October) planting and winterization' : m.climate.includes('humid') ? 'year-round maintenance with spring and fall planting seasons; summer mowing and irrigation management; winter pruning of deciduous plants' : 'spring and fall are the primary planting and renovation seasons; summer maintenance focuses on irrigation and mowing'}. ${m.hoods[0]} and ${m.hoods[1]} professional maintenance contracts run $150-$400 per month.`,
    stormwaterPara: `${m.display} stormwater management through landscaping: ${m.climate.includes('rain') || m.climate.includes('flood') || m.climate.includes('monsoon') ? 'rain gardens, bioswales, and permeable pavers help manage ' + m.display + "'s heavy rain events while reducing runoff. Some jurisdictions offer stormwater-fee credits for properties with on-site detention." : m.soilType.includes('clay') ? 'proper drainage is essential on ' + m.display + "'s clay soil to prevent foundation damage; landscape grading should direct water away from structures." : 'standard landscape drainage practices (grading away from structures, French drains, rain gardens) manage stormwater effectively.'} ${m.hoaDensity === 'high' ? 'HOA common-area stormwater management may affect individual lot drainage requirements.' : ''}`,
    commonScamPara: `${m.display} landscaping red flags: ${pick([
      'contractors who begin work without a written contract specifying plant species, sizes, quantities, and warranty terms',
      '"landscape design included free" offers that produce generic plans without site-specific soil testing, sun-exposure analysis, or drainage assessment',
      'quoting by the "truckload" of mulch or soil without specifying cubic yardage and application depth',
    ], s)}. Always verify ${m.stateReq.split(';')[0]} and ask for 3 references with photos of projects completed 2+ years ago to verify plant survival and design longevity.`,
  };
}

function genSiding(slug, m) {
  const s = hash(slug + "|siding");
  return {
    sec_material: `${m.display} siding material selection is driven by ${m.climate.split(',')[0]}. ${m.climate.includes('humid') || m.climate.includes('salt') ? 'Fiber cement and engineered wood handle the moisture better than vinyl (which warps under direct sun) or natural wood (which rots in 8-12 years). Salt-air corrosion at the waterfront demands stainless-steel or hot-dipped galvanized fasteners.' : m.climate.includes('UV') || m.climate.includes('desert') ? 'Stucco and fiber cement dominate because UV degrades standard vinyl within 8-10 years. Wood siding dries and cracks in the intense sun.' : m.climate.includes('freeze') ? 'Fiber cement and insulated vinyl handle freeze-thaw cycling best; standard vinyl can crack below -20F and wood expands and contracts enough to pop nails.' : 'Fiber cement, vinyl, and engineered wood all perform well; material choice is driven more by aesthetics and budget than climate requirements.'} ${m.hoods[0]} and ${m.hoods[1]} favor ${pick(['fiber cement (James Hardie) for its longevity and paint-holding ability', 'LP SmartSide engineered wood for its natural appearance', 'high-quality vinyl with lifetime color warranty'], s)}.`,
    sec_climate: `${m.display}'s ${m.climate.split(',')[0]} affects siding differently than interior trades: ${pick([`UV intensity on south and west exposures accelerates color fading and material degradation 30-40% faster than shaded or north-facing surfaces`, `the ${m.climate.includes('humidity') || m.climate.includes('humid') ? 'constant moisture' : 'seasonal temperature cycling'} drives fastener corrosion and joint expansion that contractors must anticipate during installation`, `windborne debris from ${m.naturalHazard.split(',')[0]} creates impact risk that affects material selection and insurance requirements`], s)}. ${m.hoods[0]} homes face the full climate exposure while ${m.hoods[2]} properties may be partially sheltered.`,
    sec_code: `${m.permitAuth} regulates siding replacement in ${m.display}. ${m.stateReq}. Most like-for-like siding replacements require permits; changes to material type, wall structure, or exterior appearance in ${m.historicDistricts ? 'historic districts (' + m.historicDistricts + ') require additional design review' : 'regulated neighborhoods may require additional review'}. ${m.climate.includes('wind') || m.naturalHazard.includes('hurricane') ? 'Wind-speed design requirements may mandate specific fastener patterns and installation methods.' : ''}`,
    sec_insurance: `Siding damage claims in ${m.display} follow ${m.naturalHazard.split(',')[0]} events. ${m.naturalHazard.includes('hail') ? 'Hail damage to siding is covered under most homeowners policies with standard deductibles; verify your policy covers matching (replacing all sides to match, not just the damaged side).' : m.naturalHazard.includes('wind') || m.naturalHazard.includes('hurricane') ? 'Wind damage claims may trigger minimum wind-speed requirements for replacement materials.' : 'Standard homeowners insurance covers weather-related siding damage; verify your policy terms for matching and depreciation.'} ${m.display} homeowners should document existing siding condition annually with dated photos.`,
    sec_contractor: `${m.display}'s ${m.pop > 500000 ? 'large market supports material-specific siding contractors who work faster and price lower than general contractors' : 'mid-size market has a mix of dedicated siding contractors and general exterior contractors'}. ${m.growth === 'high' ? 'Rapid growth has attracted siding contractors from outside the metro; verify local licensing.' : ''} For fiber cement (James Hardie), verify the crew has Hardie-specific installation certification; improper installation voids the 30-year material warranty. ${m.hoods[0]} and ${m.hoods[1]} generate the highest siding replacement volume.`,
    sec_flag: `${m.display} siding red flags: ${pick(['contractors who don\'t specify caulk/sealant brand and type at joints', 'quotes that omit house-wrap replacement behind new siding', 'fiber cement installers without James Hardie or LP manufacturer training'], s)}. ${pick(['Storm-chaser crews appearing after weather events with aggressive door-to-door solicitation are the highest-risk operators.', 'Bids that are 30%+ below other quotes usually indicate shortcuts on house-wrap, flashing, or fastener quality.', 'Any contractor who asks for more than 30% upfront before materials are ordered is a red flag.'], s + 1)}`,
    dominantMaterial: pick(["fiber cement (James Hardie)", "vinyl (CertainTeed, Alside)", "engineered wood (LP SmartSide)"], s),
    climateBand: m.climate.includes('desert') ? "hot-dry" : m.climate.includes('humid') ? "mixed-humid" : m.climate.includes('cold') || m.climate.includes('freeze') ? "cold" : "moderate",
    bestSeasons: pick(["September through November", "April through June", "March through May"], s),
    worstSeasons: pick(["January through March (cold and wet)", "July through August (extreme heat)", "December through February (weather delays)"], s),
  };
}

function genWindows(slug, m) {
  const s = hash(slug + "|windows");
  const uTarget = m.climate.includes('cold') || m.climate.includes('freeze') ? 0.25 : m.climate.includes('hot') || m.climate.includes('desert') ? 0.30 : 0.28;
  return {
    sec_energy: `Window energy performance in ${m.display} is driven by ${m.climate.includes('hot') || m.climate.includes('desert') ? 'solar heat gain (SHGC) on south and west exposures -- spec Low-E coatings with SHGC under 0.30 to minimize cooling load' : m.climate.includes('cold') || m.climate.includes('freeze') ? 'U-factor (thermal conductivity) -- values under ' + uTarget + ' pay back through reduced heating costs within 7-10 years at ' + m.display + "'s utility rates" : 'both U-factor and SHGC in balanced proportion -- the dual heating/cooling load in ' + m.display + " means windows need to perform well in both directions"}. ${m.hoods[0]} and ${m.hoods[1]} homeowners investing in window replacement should prioritize energy specs that match ${m.display}'s climate rather than defaulting to whatever the installer stocks.`,
    sec_energy2: `At $${m.electricRate.toFixed(2)}/kWh, ${m.display}'s electricity rate makes ${m.electricRate > 0.20 ? 'high-performance windows a faster payback investment than low-rate markets; the energy savings from triple-pane or high-SHGC-control glass recover the $100-$200 per-window premium within 5-8 years' : m.electricRate > 0.14 ? 'window energy upgrades a moderate payback investment; prioritize the most climate-critical specification (U-factor in cold climates, SHGC in hot)' : 'window energy upgrades a longer payback investment; focus on comfort and noise-reduction benefits rather than energy savings alone'}.`,
    sec_installer: `${m.display}'s window replacement market: ${m.pop > 500000 ? 'national window companies (Renewal by Andersen, Pella, Window World) compete with independent installers using manufacturer-direct windows; national brands typically quote 40-60% higher than independents for comparable glass specs' : Math.round(m.pop / 100000) + '-' + Math.round(m.pop / 60000) + ' window replacement companies serve the ' + m.display + ' market'}. Compare at least 3 quotes on identical window specifications (brand, U-factor, SHGC, frame material) to normalize pricing. ${m.hoods[0]} and ${m.hoods[1]} properties with ${m.avgAge >= 50 ? 'non-standard vintage window openings may need custom-sized windows that add 15-30% to material cost' : 'standard window openings accept both retrofit and full-frame replacement options'}.`,
    sec_glass: `Glass options for ${m.display}: ${m.climate.includes('hot') || m.climate.includes('desert') ? 'triple-pane with low SHGC (0.20-0.25) on west exposures provides the best summer comfort; standard double-pane Low-E serves north and east exposures adequately' : m.climate.includes('cold') || m.climate.includes('freeze') ? 'argon-filled triple-pane with U-factor under ' + uTarget + ' provides the best winter performance; the incremental cost over double-pane pays back in 7-10 years at ' + m.display + "'s heating costs" : 'double-pane Low-E with argon fill provides the optimal balance of cost and performance for ' + m.display + "'s moderate climate; triple-pane is justified on north exposures in heating-dominant homes"}. ${m.naturalHazard.includes('hurricane') || m.naturalHazard.includes('wind') ? 'Impact-rated glass adds 25-40% but may be required by code or insurance.' : ''}`,
    sec_code: `${m.permitAuth} handles window replacement permits. ${m.stateReq}. Like-for-like replacements (same size, same opening) typically require permits but have streamlined processing. Changes to window size, egress requirements, or structural headers require full permit review. ${m.historicDistricts ? 'Historic district properties in ' + m.historicDistricts + ' face design review for any visible window changes, which may constrain frame material, divided-lite patterns, and profile dimensions.' : ''}`,
    sec_housing: `${m.homeEra}. Window replacement scope in ${m.display}: ${m.avgAge >= 50 ? m.hoods[0] + ' and ' + m.hoods[1] + ' homes from this era commonly have single-pane or early double-pane windows with aluminum frames that are long past their performance life; full-frame replacement is typically recommended over retrofit (insert) when the existing frames show rot or frame distortion' : m.avgAge >= 35 ? 'homes in ' + m.hoods[0] + ' and ' + m.hoods[1] + ' with original double-pane windows from this era are approaching the seal-failure point where argon gas escapes and condensation appears between panes; retrofit (insert) replacement is usually adequate when existing frames are structurally sound' : 'newer homes with functional double-pane windows may not justify replacement on energy grounds alone; prioritize windows with visible condensation, drafts, or operational failures'}.`,
    sec_storm: `${m.naturalHazard.includes('hurricane') || m.naturalHazard.includes('wind') ? m.display + "'s storm risk drives specific window requirements: impact-rated glass or approved storm shutters may be required by code in certain zones. Insurance carriers increasingly require impact protection for favorable premium rates. Budget 25-40% above standard glass prices for impact-rated units." : m.naturalHazard.includes('hail') ? 'Hail risk in ' + m.display + ' rarely requires impact-rated glass for residential windows, but tempered glass on vulnerable exposures adds modest cost and significant peace of mind.' : m.display + "'s moderate storm risk does not drive impact-glass requirements for residential windows. Standard laminated glass provides adequate storm performance for the occasional severe weather event."}`,
    sec_flag: `${m.display} window replacement red flags: ${pick(['in-home sales presentations that quote $1,200-$1,500 per window for standard vinyl double-hung when the market rate is $400-$700 installed', '"limited time" pricing pressure that evaporates if you ask for 48 hours to get competing bids', 'companies that won\'t provide the window manufacturer\'s name, model number, U-factor, and SHGC specs in writing'], s)}. The window industry has among the highest markup variability of any home trade -- getting 3+ quotes is essential.`,
    dominantMaterial: pick(["vinyl double-hung", "fiberglass casement", "vinyl sliding"], s),
    climateBand: m.climate.includes('desert') ? "hot-dry" : m.climate.includes('humid') ? "mixed-humid" : m.climate.includes('cold') || m.climate.includes('freeze') ? "cold" : "moderate",
    uTarget: uTarget,
    bestSeasons: pick(["April through October", "March through November", "September through May"], s),
    worstSeasons: pick(["December through February (cold-air exposure during swap)", "July through August (sealant cures too fast)", "January through March (weather delays)"], s),
  };
}

// ─── MAIN ───────────────────────────────────────────────────────────────

function main() {
  const vertGenerators = {
    "roofing": genRoofing,
    "electrical": genElectrical,
    "plumbing": genPlumbing,
    "solar": genSolar,
    "painting": genPainting,
    "kitchen": genKitchen,
    "fencing": genFence,
    "concrete": genConcrete,
    "foundation": genFoundation,
    "garage-door": genGarageDoor,
    "gutters": genGutters,
    "insulation": genInsulation,
    "landscaping": genLandscaping,
    "siding": genSiding,
    "windows": genWindows,
  };

  for (const [vslug, genFn] of Object.entries(vertGenerators)) {
    const output = {};
    for (const [slug, profile] of Object.entries(METRO_PROFILES)) {
      output[slug] = genFn(slug, profile);
    }
    const outPath = path.join(outDir, `${vslug}-new-metros.json`);
    fs.writeFileSync(outPath, JSON.stringify(output, null, 2), "utf8");
    console.log(`${vslug}: generated ${Object.keys(output).length} metro entries -> ${outPath}`);
  }

  console.log(`\nDone. Data files in ${outDir}/`);
  console.log("Next: merge into each build-flagship-*.js data dictionary.");
}

main();
